import IconAdjuster from './features/toolbox/IconAdjuster';
import { AppState, IconItem, IconAdjusterData } from './types';

// Simple Background Component
const MinimalBackground = () => (
  <div className="fixed inset-0 z-[-1]">
    <div className="absolute inset-0 bg-zinc-950" />
    <div className="absolute inset-0 bg-gradient-to-br from-zinc-950 via-slate-950 to-black" />
    <div className="absolute top-0 left-0 w-full h-[500px] bg-gradient-to-b from-indigo-900/20 to-transparent opacity-50 blur-3xl pointer-events-none" />
  </div>
);

const INITIAL_STATE: AppState = {
  language: 'en',
  iconAdjusterData: {
    items: [], 
    selectedItemIds: [], 
    commandMode: 'one', 
    canvasWidth: 512, 
    canvasHeight: 512,
    background: 'transparent', 
    backgroundColor: '#ffffff', 
    strokeEnabled: false, 
    strokeColor: '#000000',
    strokeThickness: 2, 
    strokeSmoothness: 8, 
    strokeBlur: 0, 
    moveStep: 10, 
    scaleStep: 0.1, 
    fitPadding: 20, 
    cropThreshold: 10, 
    gridColumns: 5
  }
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(INITIAL_STATE);

  const updateState = (updates: Partial<AppState>) => {
    setState(prev => ({ ...prev, ...updates }));
  };

  const updateIconAdjusterData = (updates: Partial<IconAdjusterData>) => {
    updateState({
        iconAdjusterData: { ...state.iconAdjusterData, ...updates }
    });
  };

  const updateIconItem = (idOrIds: string | string[], updates: Partial<IconItem>) => {
      const ids = Array.isArray(idOrIds) ? idOrIds : [idOrIds];
      updateIconAdjusterData({
          items: state.iconAdjusterData.items.map(item => ids.includes(item.id) ? { ...item, ...updates } : item)
      });
  };

  const handleIconUpload = (files: FileList) => {
      const newItems: IconItem[] = Array.from(files).map(file => ({
          id: Date.now().toString() + Math.random(),
          file,
          src: URL.createObjectURL(file),
          x: 0, y: 0, scale: 1,
          originalWidth: 512, originalHeight: 512
      }));

      newItems.forEach(item => {
          const img = new Image();
          img.onload = () => {
              item.originalWidth = img.naturalWidth;
              item.originalHeight = img.naturalHeight;
          };
          img.src = item.src;
      });

      updateIconAdjusterData({
          items: [...state.iconAdjusterData.items, ...newItems]
      });
  };

  return (
    <div className="relative min-h-screen text-white font-sans overflow-hidden flex flex-col">
      <MinimalBackground />

      {/* Header with 3 Beautiful Buttons */}
      <header className="w-full max-w-7xl mx-auto p-6 flex flex-col md:flex-row items-center justify-between gap-6 z-10">
        <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
                <span className="text-xl font-bold">S</span>
            </div>
            <h1 className="text-xl font-bold tracking-tight text-transparent bg-clip-text bg-gradient-to-r from-white to-zinc-400">
                Icon Adjuster
            </h1>
        </div>

        <nav className="flex items-center gap-4">
            {[
                { label: 'My Portfolio', href: '#' },
                { label: 'Documentation', href: '#' },
                { label: 'Contact Support', href: '#' }
            ].map((btn, idx) => (
                <a 
                    key={idx}
                    href={btn.href}
                    className="relative group px-6 py-2.5 rounded-full overflow-hidden transition-all duration-300 hover:scale-105"
                >
                    <div className="absolute inset-0 bg-zinc-800/50 backdrop-blur-md border border-zinc-700/50 rounded-full transition-colors group-hover:bg-zinc-700/50 group-hover:border-zinc-600" />
                    <div className="absolute inset-0 bg-gradient-to-r from-indigo-500/10 to-purple-500/10 opacity-0 group-hover:opacity-100 transition-opacity" />
                    <span className="relative text-sm font-medium text-zinc-200 group-hover:text-white transition-colors">
                        {btn.label}
                    </span>
                </a>
            ))}
        </nav>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col max-w-[1920px] mx-auto w-full h-[calc(100vh-88px)] p-4 md:p-6 pb-0">
          <div className="flex-1 bg-zinc-900/40 backdrop-blur-xl border border-zinc-800 rounded-t-3xl overflow-hidden shadow-2xl relative">
              <IconAdjuster 
                  state={state} 
                  handleIconUpload={handleIconUpload}
                  updateIconAdjusterData={updateIconAdjusterData}
                  updateIconItem={updateIconItem}
              />
          </div>
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; height: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: rgba(9,9,11,0.5); }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(63,63,70,0.5); border-radius: 3px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(161,161,170,0.5); }
        .animate-fade-in-up { animation: fadeInUp 0.5s ease-out forwards; }
        @keyframes fadeInUp { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
    </div>
  );
};

export default App;

export type Language = 'en' | 'th';

export interface IconOverlay {
  src: string;
  x: number;
  y: number;
  scale: number;
  rotation: number;
}

export interface IconItem {
  id: string;
  file: File;
  src: string; // Object URL
  x: number;
  y: number;
  scale: number;
  originalWidth: number;
  originalHeight: number;
  overlay?: IconOverlay;
}

export type IconCommandMode = 'one' | 'multi' | 'all';

export interface IconAdjusterData {
  items: IconItem[];
  selectedItemIds: string[]; // Array for multi-select
  commandMode: IconCommandMode;
  canvasWidth: number;
  canvasHeight: number;
  background: 'transparent' | 'white' | 'black' | 'custom';
  backgroundColor: string;
  strokeEnabled: boolean;
  strokeColor: string;
  strokeThickness: number;
  strokeSmoothness: number;
  strokeBlur: number;
  moveStep: number;
  scaleStep: number;
  fitPadding: number;
  cropThreshold: number; // 0-255
