import { HarmonyType } from "../types";

// Simple Hex to HSL conversion
export const hexToHSL = (hex: string): { h: number, s: number, l: number } => {
  let r = 0, g = 0, b = 0;
  if (hex.length === 4) {
    r = parseInt("0x" + hex[1] + hex[1]);
    g = parseInt("0x" + hex[2] + hex[2]);
    b = parseInt("0x" + hex[3] + hex[3]);
  } else if (hex.length === 7) {
    r = parseInt("0x" + hex[1] + hex[2]);
    g = parseInt("0x" + hex[3] + hex[4]);
    b = parseInt("0x" + hex[5] + hex[6]);
  }
  r /= 255; g /= 255; b /= 255;
  const cmin = Math.min(r,g,b), cmax = Math.max(r,g,b), delta = cmax - cmin;
  let h = 0, s = 0, l = 0;

  if (delta === 0) h = 0;
  else if (cmax === r) h = ((g - b) / delta) % 6;
  else if (cmax === g) h = (b - r) / delta + 2;
  else h = (r - g) / delta + 4;

  h = Math.round(h * 60);
  if (h < 0) h += 360;

  l = (cmax + cmin) / 2;
  s = delta === 0 ? 0 : delta / (1 - Math.abs(2 * l - 1));

  return { h, s, l };
};

// Simple HSL to Hex conversion
export const hslToHex = (h: number, s: number, l: number): string => {
  let c = (1 - Math.abs(2 * l - 1)) * s,
      x = c * (1 - Math.abs(((h / 60) % 2) - 1)),
      m = l - c / 2,
      r = 0, g = 0, b = 0;

  if (0 <= h && h < 60) { r = c; g = x; b = 0; }
  else if (60 <= h && h < 120) { r = x; g = c; b = 0; }
  else if (120 <= h && h < 180) { r = 0; g = c; b = x; }
  else if (180 <= h && h < 240) { r = 0; g = x; b = c; }
  else if (240 <= h && h < 300) { r = x; g = 0; b = c; }
  else if (300 <= h && h < 360) { r = c; g = 0; b = x; }

  r = Math.round((r + m) * 255);
  g = Math.round((g + m) * 255);
  b = Math.round((b + m) * 255);

  const toHex = (n: number) => {
    const hex = n.toString(16);
    return hex.length === 1 ? "0" + hex : hex;
  };
  return "#" + toHex(r) + toHex(g) + toHex(b);
};

export const randomizeHue = (hex: string): string => {
  const { s, l } = hexToHSL(hex);
  const newH = Math.floor(Math.random() * 360);
  return hslToHex(newH, s, l);
};

export const rgbToHex = (r: number, g: number, b: number): string => {
  return "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
};

// Calculate Harmony Palette
export const calculateHarmonyPalette = (baseHex: string, type: HarmonyType): string[] => {
    const { h, s, l } = hexToHSL(baseHex);
    const palette: string[] = [baseHex]; // Base color is always first

    const addColor = (hueOffset: number) => {
        let newH = (h + hueOffset) % 360;
        if (newH < 0) newH += 360;
        palette.push(hslToHex(newH, s, l));
    };

    switch (type) {
        case 'primary': // Approximating standard RYB triadic feel or just RGB primaries
             addColor(120);
             addColor(240);
             break;
        case 'analogous':
            addColor(30);
            addColor(-30);
            break;
        case 'complementary':
            addColor(180);
            break;
        case 'split_complementary':
            addColor(150);
            addColor(210);
            break;
        case 'double_split_complementary':
            addColor(30);
            addColor(180);
            addColor(210);
            break;
        case 'triadic':
            addColor(120);
            addColor(240);
            break;
        case 'square':
            addColor(90);
            addColor(180);
            addColor(270);
            break;
        case 'tetradic': // Rectangle
            addColor(60);
            addColor(180);
            addColor(240);
            break;
    }
    return palette;
};

export const polarToCartesian = (radius: number, angleDegrees: number) => {
  const angleRadians = (angleDegrees - 90) * (Math.PI / 180.0);
  return {
    x: radius * Math.cos(angleRadians),
    y: radius * Math.sin(angleRadians)
  };
};

import { EditorLayer } from '../../../types';

// Calculate bounds for a list of layers
export const getBoundsForLayers = (layers: EditorLayer[]) => {
    if (layers.length === 0) return null;
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    layers.forEach(l => {
        const halfW = l.width / 2;
        const halfH = l.height / 2;
        minX = Math.min(minX, l.x - halfW);
        minY = Math.min(minY, l.y - halfH);
        maxX = Math.max(maxX, l.x + halfW);
        maxY = Math.max(maxY, l.y + halfH);
    });
    return { x: minX, y: minY, w: maxX - minX, h: maxY - minY, cx: (minX + maxX) / 2, cy: (minY + maxY) / 2 };
};

// Get mouse position relative to canvas
export const getLocalMousePos = (clientX: number, clientY: number, rect: DOMRect, canvasWidth: number, canvasHeight: number) => {
    const scaleX = canvasWidth / rect.width;
    const scaleY = canvasHeight / rect.height;
    return { x: (clientX - rect.left) * scaleX, y: (clientY - rect.top) * scaleY };
};

import { ImageEditorData } from '../../../types';
import { drawShapePath, SHAPE_LIBRARY } from '../../../utils/shapeDrawer';
import { getBoundsForLayers } from './utils';

export const renderCanvas = (
    ctx: CanvasRenderingContext2D,
    data: ImageEditorData,
    isPanning: boolean
) => {
    ctx.clearRect(0, 0, data.canvasWidth, data.canvasHeight);

    // 1. Render Layers
    data.layers.forEach(layer => {
        if (!layer.visible) return;

        ctx.save();
        ctx.globalAlpha = layer.opacity / 100;
        ctx.translate(layer.x, layer.y);
        ctx.rotate((layer.rotation * Math.PI) / 180);

        const halfW = layer.width / 2;
        const halfH = layer.height / 2;

        if (layer.type === 'frame') {
            // Define Path
            drawShapePath(ctx, layer.shapeType || 'square', layer.width, layer.height, { 
                cornerRadii: layer.cornerRadii,
                cornerRadius: layer.cornerRadius 
            });

            // Clip
            ctx.save();
            ctx.clip();

            // Draw Inner Image
            if (layer.frameImage && layer.frameImage.src) {
                const img = new Image();
                img.src = layer.frameImage.src;

                // Inner transform relative to center
                const ix = layer.frameImage.x;
                const iy = layer.frameImage.y;
                const iscale = layer.frameImage.scale;
                const irot = layer.frameImage.rotation;

                ctx.translate(ix, iy);
                ctx.rotate((irot * Math.PI) / 180);
                ctx.scale(iscale, iscale);

                const iw = layer.frameImage.originalWidth;
                const ih = layer.frameImage.originalHeight;
                ctx.drawImage(img, -iw / 2, -ih / 2, iw, ih);
            } else {
                // Placeholder
                ctx.fillStyle = '#27272a'; // zinc-800
                ctx.fill();
                // Draw cross/icon?
                ctx.strokeStyle = '#52525b';
                ctx.lineWidth = 1;
                ctx.beginPath();
                ctx.moveTo(-halfW * 0.5, -halfH * 0.5); ctx.lineTo(halfW * 0.5, halfH * 0.5);
                ctx.moveTo(halfW * 0.5, -halfH * 0.5); ctx.lineTo(-halfW * 0.5, halfH * 0.5);
                ctx.stroke();
            }
            ctx.restore(); // Restore clip

            // Draw Stroke (Border) on top
            if (layer.strokeWidth && layer.strokeWidth > 0) {
                drawShapePath(ctx, layer.shapeType || 'square', layer.width, layer.height, {
                    cornerRadii: layer.cornerRadii,
                    cornerRadius: layer.cornerRadius
                });
                ctx.strokeStyle = layer.strokeColor || '#000';
                ctx.lineWidth = layer.strokeWidth;
                ctx.stroke();
            }

        } else if (layer.type === 'image' && layer.src) {
            if (layer.filters) {
                const f = layer.filters;
                ctx.filter = `brightness(${f.brightness}%) contrast(${f.contrast}%) saturate(${f.saturation}%) blur(${f.blur}px) hue-rotate(${f.hue}deg) sepia(${f.sepia}%) grayscale(${f.grayscale}%)`;
            }

            const img = new Image();
            img.src = layer.src;

            if (layer.tintColor) {
                const offCanvas = document.createElement('canvas');
                offCanvas.width = layer.width;
                offCanvas.height = layer.height;
                const offCtx = offCanvas.getContext('2d');
                if (offCtx) {
                    offCtx.drawImage(img, 0, 0, layer.width, layer.height);
                    offCtx.globalCompositeOperation = 'source-in';
                    offCtx.fillStyle = layer.tintColor;
                    offCtx.fillRect(0, 0, layer.width, layer.height);
                    ctx.drawImage(offCanvas, -halfW, -halfH);
                }
            } else {
                ctx.drawImage(img, -halfW, -halfH, layer.width, layer.height);
            }

        } else if (layer.type === 'solid') {
            if (layer.fillType === 'gradient' && layer.gradientStops) {
                const angRad = ((layer.gradientAngle || 90) - 90) * (Math.PI / 180);
                const cos = Math.cos(angRad);
                const sin = Math.sin(angRad);

                const gradLen = Math.abs(halfW * cos) + Math.abs(halfH * sin);
                const x0 = -cos * gradLen;
                const y0 = -sin * gradLen;
                const x1 = cos * gradLen;
                const y1 = sin * gradLen;

                const grad = ctx.createLinearGradient(x0, y0, x1, y1);
                layer.gradientStops.forEach((col, i) => {
                    const pos = layer.gradientStopPositions && layer.gradientStopPositions.length === layer.gradientStops!.length
                        ? layer.gradientStopPositions[i]
                        : i / Math.max(1, layer.gradientStops!.length - 1);
                    grad.addColorStop(pos, col);
                });
                ctx.fillStyle = grad;
            } else {
                ctx.fillStyle = layer.color || '#000';
            }
            ctx.fillRect(-halfW, -halfH, layer.width, layer.height);

        } else if (layer.type === 'shape') {
            drawShapePath(ctx, layer.shapeType || 'circle', layer.width, layer.height, { 
                cornerRadii: layer.cornerRadii,
                cornerRadius: layer.cornerRadius 
            });

            if (layer.fillType !== 'none') {
                if (layer.fillType === 'gradient' && layer.gradientStops) {
                    const angRad = ((layer.gradientAngle || 90) - 90) * (Math.PI / 180);
                    const cos = Math.cos(angRad);
                    const sin = Math.sin(angRad);

                    // Logic to ensure gradient covers shape at any angle
                    const gradLen = Math.abs(halfW * cos) + Math.abs(halfH * sin);
                    const x0 = -cos * gradLen;
                    const y0 = -sin * gradLen;
                    const x1 = cos * gradLen;
                    const y1 = sin * gradLen;

                    const grad = ctx.createLinearGradient(x0, y0, x1, y1);
                    layer.gradientStops.forEach((col, i) => {
                        // Use explicit position if available, otherwise distribute evenly
                        const pos = layer.gradientStopPositions && layer.gradientStopPositions.length === layer.gradientStops!.length
                            ? layer.gradientStopPositions[i]
                            : i / Math.max(1, layer.gradientStops!.length - 1);
                        grad.addColorStop(pos, col);
                    });
                    ctx.fillStyle = grad;
                } else {
                    ctx.fillStyle = layer.color || '#000';
                }
                ctx.fill();
            }

            if (layer.strokeWidth && layer.strokeWidth > 0) {
                ctx.strokeStyle = layer.strokeColor || '#000';
                ctx.lineWidth = layer.strokeWidth;
                ctx.stroke();
            }
        }
        ctx.restore();
    });

    // 2. Render Selection UI
    if (data.activeTool === 'move' && data.selectedLayerIds.length > 0 && !isPanning) {
        if (data.selectedLayerIds.length === 1) {
            // Single Selection Handles
            const l = data.layers.find(ly => ly.id === data.selectedLayerIds[0]);
            if (l) {
                ctx.save();
                ctx.translate(l.x, l.y);
                ctx.rotate((l.rotation * Math.PI) / 180);

                ctx.strokeStyle = '#3b82f6';
                ctx.lineWidth = 1;
                ctx.setLineDash([5, 5]);
                ctx.strokeRect(-l.width/2, -l.height/2, l.width, l.height);

                ctx.setLineDash([]);
                ctx.fillStyle = 'white';
                ctx.strokeStyle = '#3b82f6';
                const s = 8; 
                const hs = s/2;
                const hw = l.width/2;
                const hh = l.height/2;

                const handles = [{ x: -hw, y: -hh }, { x: hw, y: -hh }, { x: -hw, y: hh }, { x: hw, y: hh }];
                handles.forEach(h => {
                    ctx.fillRect(h.x - hs, h.y - hs, s, s);
                    ctx.strokeRect(h.x - hs, h.y - hs, s, s);
                });

                // Rotation Handle
                ctx.beginPath();
                ctx.moveTo(0, -hh);
                ctx.lineTo(0, -hh - 20);
                ctx.stroke();
                ctx.beginPath();
                ctx.arc(0, -hh - 20, 5, 0, Math.PI*2);
                ctx.fill();
                ctx.stroke();
                ctx.restore();
            }

        } else {
            // Multi-Selection Bounds
            const bounds = getBoundsForLayers(data.layers.filter(l => data.selectedLayerIds.includes(l.id)));
            if (bounds) {
                const { x, y, w, h } = bounds;
                ctx.save();
                ctx.strokeStyle = '#3b82f6';
                ctx.lineWidth = 1;
                ctx.setLineDash([5, 5]);
                ctx.strokeRect(x, y, w, h);
                ctx.setLineDash([]);
                ctx.fillStyle = 'white';
                ctx.strokeStyle = '#3b82f6';
                const s = 8;
                const handles = [{ x: x, y: y }, { x: x + w, y: y }, { x: x, y: y + h }, { x: x + w, y: y + h }];
                handles.forEach(h => {
                    ctx.fillRect(h.x - s/2, h.y - s/2, s, s);
                    ctx.strokeRect(h.x - s/2, h.y - s/2, s, s);
                });
                ctx.restore();
            }
        }
    }

    // 3. Render Crop Rect
    if (data.activeTool === 'crop' && data.cropRect) {
        ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
        const cr = data.cropRect;
        ctx.fillRect(0, 0, data.canvasWidth, cr.y);
        ctx.fillRect(0, cr.y + cr.h, data.canvasWidth, data.canvasHeight - (cr.y + cr.h));
        ctx.fillRect(0, cr.y, cr.x, cr.h);
        ctx.fillRect(cr.x + cr.w, cr.y, data.canvasWidth - (cr.x + cr.w), cr.h);
        ctx.strokeStyle = 'white';
        ctx.lineWidth = 2;
        ctx.strokeRect(cr.x, cr.y, cr.w, cr.h);
    }
};

