export const useAppLogic = () => {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activePopover, setActivePopover] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const autoFillInputRef = useRef<HTMLInputElement>(null);
  const hairRefInputRef = useRef<HTMLInputElement>(null);
  const latestImageRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const updateState = useCallback((updates: Partial<AppState> | ((prev: AppState) => Partial<AppState>)) => {
    setState((prev) => {
        const newValues = typeof updates === 'function' ? updates(prev) : updates;
        return { ...prev, ...(newValues as Partial<AppState>) };
    });
  }, []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateState({ referenceImage: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    const file = e.dataTransfer.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateState({ referenceImage: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const clearReferenceImage = () => updateState({ referenceImage: null });

  // Data Updaters
  const createUpdater = <T extends keyof AppState>(key: T) => (field: keyof AppState[T], value: any) => {
      updateState((prev) => ({
          ...prev,
          [key]: { ...prev[key], [field]: value }
      }));
  };

  const updateCharacterData = createUpdater('characterData');
  const updateEnvironmentData = createUpdater('environmentData');
  const updateGamePropsData = createUpdater('gamePropsData');
  const updateUserInterfaceData = createUpdater('userInterfaceData');
  const updateUIAssetData = createUpdater('uiAssetData');
  const updateIconDesignData = createUpdater('iconDesignData');
  const updateVariantData = createUpdater('variantData');
  const updateSoundEffectData = createUpdater('soundEffectData');

  const updateEditState = (updates: Partial<EditState>) => {
      updateState((prev) => ({
          ...prev,
          editState: { ...prev.editState, ...updates }
      }));
  };

  const updateCreatureMix = (id: string, key: string, value: any) => {
      updateState(prev => ({
          creatureMixes: prev.creatureMixes.map(mix => mix.id === id ? { ...mix, [key]: value } : mix)
      }));
  };

  const addCreatureMix = () => {
      updateState(prev => {
          if (prev.creatureMixes.length >= 4) return {};
          return { creatureMixes: [...prev.creatureMixes, { id: Date.now().toString(), name: '', percentage: 50 }] };
      });
  };

  const removeCreatureMix = (id: string) => {
      updateState(prev => {
          if (prev.creatureMixes.length <= 1) return {};
          return { creatureMixes: prev.creatureMixes.filter(m => m.id !== id) };
      });
  };

  const updateCreatureAdvanced = createUpdater('creatureAdvanced');

  const handleGeneratePalette = (overrideBase?: string) => {
      updateState(prev => {
          const base = overrideBase || prev.variantData.baseColor;
          const palette = calculateHarmonyPalette(base, prev.variantData.harmonyType);
          return {
              variantData: { ...prev.variantData, generatedPalette: palette, baseColor: base }
          };
      });
  };

  // --- Texture Generator Logic ---
  const handleTextureGridUpdate = (rows: number, cols: number) => {
      updateState(prev => {
          const currentCount = prev.textureGeneratorData.slots.length;
          const targetCount = rows * cols;
          let newSlots = [...prev.textureGeneratorData.slots];

          if (targetCount > currentCount) {
              for(let i = currentCount; i < targetCount; i++) {
                  newSlots.push({ id: Date.now().toString() + i, type: 'solid' as const, colors: ['#ffffff'], angle: 0 });
              }
          } else {
              newSlots = newSlots.slice(0, targetCount);
          }
          return { textureGeneratorData: { ...prev.textureGeneratorData, rows, cols, slots: newSlots } };
      });
  };

  const updateTextureSlot = (id: string, updates: Partial<TextureSlot>) => {
      updateState(prev => ({
          textureGeneratorData: {
              ...prev.textureGeneratorData,
              slots: prev.textureGeneratorData.slots.map(s => s.id === id ? { ...s, ...updates } : s)
          }
      }));
  };

  const randomizeSlot = (id: string) => {
      const randomColor = () => '#' + Math.floor(Math.random()*16777215).toString(16).padStart(6, '0');
      const isGradient = Math.random() > 0.5;
      updateTextureSlot(id, {
          type: isGradient ? ('gradient' as const) : ('solid' as const),
          colors: isGradient ? [randomColor(), randomColor()] : [randomColor()],
          angle: Math.floor(Math.random() * 360)
      });
  };

  const handleForceAngle = (id: string, angle: number) => {
      updateTextureSlot(id, { angle });
  };

  const handleVariantHue = (id: string) => {
      const slot = state.textureGeneratorData.slots.find(s => s.id === id);
      if (!slot) return;

      const newColors = slot.colors.map(col => randomizeHue(col));
      updateTextureSlot(id, { colors: newColors });
  };

  const handleTextureScan = (file: File, padding: number) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          const img = new Image();
          img.onload = () => {
              const canvas = document.createElement('canvas');
              canvas.width = img.width;
              canvas.height = img.height;
              const ctx = canvas.getContext('2d');
              if (!ctx) return;
              ctx.drawImage(img, 0, 0);

              const rows = state.textureGeneratorData.rows;
              const cols = state.textureGeneratorData.cols;
              const slotW = img.width / cols;
              const slotH = img.height / rows;

              const newSlots = state.textureGeneratorData.slots.map((slot, index) => {
                  if (index >= rows * cols) return slot;

                  const r = Math.floor(index / cols);
                  const c = index % cols;

                  const x = c * slotW;
                  const y = r * slotH;

                  // Sample Top (Start)
                  const p1 = ctx.getImageData(x + slotW/2, y + padding, 1, 1).data;
                  const hex1 = rgbToHex(p1[0], p1[1], p1[2]);

                  // Sample Bottom (End)
                  const p2 = ctx.getImageData(x + slotW/2, y + slotH - padding, 1, 1).data;
                  const hex2 = rgbToHex(p2[0], p2[1], p2[2]);

                  return {
                      ...slot,
                      type: 'gradient' as const,
                      colors: [hex1, hex2],
                      angle: 90, // Vertical scan implies 90 deg
                      stops: [0, 100]
                  };
              });

              updateState(prev => ({
                  textureGeneratorData: { ...prev.textureGeneratorData, slots: newSlots }
              }));
          };
          img.src = e.target?.result as string;
      };
      reader.readAsDataURL(file);
  };

  const handleAITextureGenerate = async (mode: 'single' | 'all') => {
      const promptText = state.textureGeneratorData.texturePrompt;
      if (!promptText) {
          alert("Please enter a description for the palette.");
          return;
      }

      if (!process.env.API_KEY) {
           console.warn("API Key missing");
           const mockColors = ['#ff00ff', '#00ffff', '#ffff00'];
           // Mock logic for demo if no key
           updateState(prev => {
                const newSlots = prev.textureGeneratorData.slots.map(s => {
                    const shouldUpdate = mode === 'all' ? !s.locked : s.id === prev.textureGeneratorData.selectedSlotId;
                    if (shouldUpdate) {
                        return {
                            ...s,
                            type: 'gradient' as const,
                            colors: mockColors.sort(() => Math.random() - 0.5),
                            angle: Math.floor(Math.random() * 360)
                        };
                    }
                    return s;
                });
                return { textureGeneratorData: { ...prev.textureGeneratorData, slots: newSlots } };
           });
           return;
      }

      updateState({ isGenerating: true, generationStatus: 'Dreaming palettes...' });

      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

          const slotsToUpdate = mode === 'single' 
              ? state.textureGeneratorData.slots.filter(s => s.id === state.textureGeneratorData.selectedSlotId)
              : state.textureGeneratorData.slots.filter(s => !s.locked);

          if (slotsToUpdate.length === 0) {
               updateState({ isGenerating: false });
               return;
          }

          // Parallel generation
          const results = await Promise.all(slotsToUpdate.map(async (slot) => {
               try {
                   const response = await ai.models.generateContent({
                       model: 'gemini-2.5-flash',
                       contents: `Create a color palette of 3-5 hex codes representing the texture/theme: "${promptText}". Variation ${slot.id}.`,
                       config: {
                           responseMimeType: 'application/json',
                           responseSchema: {
                               type: Type.ARRAY,
                               items: { type: Type.STRING }
                           }
                       }
                   });
                   const colors = JSON.parse(response.text || '[]');
                   return { id: slot.id, colors };
               } catch (e) {
                   console.error(e);
                   return { id: slot.id, colors: null };
               }
          }));

          updateState(prev => {
              const newSlots = prev.textureGeneratorData.slots.map(s => {
                  const res = results.find(r => r.id === s.id);
                  if (res && res.colors && res.colors.length > 0) {
                      return {
                          ...s,
                          type: 'gradient' as const,
                          colors: res.colors,
                          angle: Math.floor(Math.random() * 360),
                          stops: undefined
                      };
                  }
                  return s;
              });
              return {
                  textureGeneratorData: { ...prev.textureGeneratorData, slots: newSlots },
                  isGenerating: false,
                  generationStatus: 'Done'
              };
          });

      } catch (error) {
          console.error(error);
          updateState({ isGenerating: false, generationStatus: 'Error' });
      }
  };

  const handleSaveJSON = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(state.textureGeneratorData));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href",     dataStr);
      downloadAnchorNode.setAttribute("download", "texture_grid.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  const handleLoadJSON = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const data = JSON.parse(event.target?.result as string);
              if (data && data.slots) {
                  updateState({ textureGeneratorData: data });
              }
          } catch (error) {
              console.error("Invalid JSON", error);
          }
      };
      reader.readAsText(file);
  };

  // --- Auto Fill ---
  const handleAutoFillClick = () => {
      autoFillInputRef.current?.click();
  };

  const onAutoFillFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
      alert("Auto Fill feature would analyze the image using Gemini Vision here.");
  };

  // --- Generation Logic ---
  const handleGenerate = async (overrideImageBase64?: string) => {
      if (state.isGenerating) return;
      updateState({ isGenerating: true, generationStatus: 'Starting...', completedCount: 0, totalBatchCount: state.mode === 'edit' ? state.editState.settings[state.editState.activeMode].batchSize : state.batchSize });

      try {
          let prompt = generatePrompt(state, TRANSLATIONS[state.language]);
          let total = state.batchSize;
          let modelToUse = state.selectedModel;
          let imageConfig: any = { aspectRatio: state.aspectRatio };

          // --- Special Logic for Edit Mode ---
          if (state.mode === 'edit') {
              const mode = state.editState.activeMode;
              prompt = state.editState.prompts[mode];
              total = state.editState.settings[mode].batchSize;

              if (mode === 'fast') {
                  modelToUse = 'gemini-2.5-flash-image';
                  imageConfig = { aspectRatio: state.editState.settings.fast.aspectRatio };
              } else {
                  modelToUse = 'gemini-3-pro-image-preview';
                  imageConfig = { 
                      aspectRatio: state.editState.settings.pro.aspectRatio,
                      imageSize: state.editState.settings.pro.resolution
                  };
              }
          } else {
              // Standard logic for other modes
              if (modelToUse === 'gemini-3-pro-image-preview') {
                  imageConfig.imageSize = state.imageSize;
              }
          }

          // --- 1. Sound Effect Generation (ElevenLabs) ---
          if (state.category === 'sound_effect') {
              const apiKey = state.soundEffectData.keyMode === 'custom' 
                  ? state.soundEffectData.apiKey 
                  : 'sk_efa5502da7cb94243d702c1d54c4e37798b8d7c6c292e816'; // Fallback key

              if (!apiKey) {
                  alert("Please provide an API Key for ElevenLabs.");
                  updateState({ isGenerating: false });
                  return;
              }

              for (let i = 0; i < total; i++) {
                  updateState({ generationStatus: `Generating sound ${i + 1}/${total}` });

                  const response = await fetch('https://api.elevenlabs.io/v1/sound-generation', {
                      method: 'POST',
                      headers: {
                          'Content-Type': 'application/json',
                          'xi-api-key': apiKey
                      },
                      body: JSON.stringify({
                          text: prompt,
                          duration_seconds: state.soundEffectData.durationSeconds,
                          prompt_influence: state.soundEffectData.promptInfluence
                      })
                  });

                  if (!response.ok) {
                      throw new Error(`ElevenLabs Error: ${response.statusText}`);
                  }

                  const blob = await response.blob();
                  const audioUrl = URL.createObjectURL(blob);

                  // Create placeholder image
                  const svgString = `<svg width="512" height="512" xmlns="http://www.w3.org/2000/svg" style="background:#18181b"><rect width="100%" height="100%" fill="#18181b"/><text x="50%" y="50%" font-family="sans-serif" font-size="24" fill="#fb7185" text-anchor="middle" dominant-baseline="middle">🔊 SFX: ${prompt.slice(0,15)}...</text></svg>`;
                  const imageUrl = `data:image/svg+xml;base64,${btoa(svgString)}`;

                  const newImg: GeneratedImage = {
                      id: Date.now().toString() + i,
                      url: imageUrl,
                      audioUrl: audioUrl,
                      prompt: prompt,
                      mode: state.mode,
                      category: state.category,
                      model: 'ElevenLabs',
                      aspectRatio: '1:1',
                      artStyle: 'none'
                  };

                  updateState(prev => ({
                      generatedImages: [...prev.generatedImages, newImg],
                      completedCount: prev.completedCount + 1
                  }));

                  // Sequential delay if batching
                  if (i < total - 1) await new Promise(r => setTimeout(r, 1000));
              }
          } 

          // --- 2. Image Generation (Gemini) ---
          else {
              if (!process.env.API_KEY) {
                  // Simulation Fallback
                  console.warn("No API Key found");
                  await new Promise(resolve => setTimeout(resolve, 2000));
                  const mockImage: GeneratedImage = {
                      id: Date.now().toString(),
                      url: 'https://via.placeholder.com/1024',
                      prompt: prompt,
                      mode: state.mode,
                      category: state.category,
                      model: modelToUse,
                      aspectRatio: imageConfig.aspectRatio,
                      artStyle: state.artStyle
                  };
                  updateState(prev => ({
                      generatedImages: [...prev.generatedImages, mockImage],
                      completedCount: total
                  }));
              } else {
                  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

                  for (let i = 0; i < total; i++) {
                      updateState({ generationStatus: `Generating image ${i + 1}/${total}` });

                      const requestContents: any = { parts: [{ text: prompt }] };

                      // Logic for Edit Mode Image Injection
                      if (state.mode === 'edit' && state.referenceImage) {
                          const base64Data = state.referenceImage.split(',')[1];
                          requestContents.parts.push({
                              inlineData: {
                                  mimeType: 'image/png', 
                                  data: base64Data
                              }
                          });
                      }

                      const response = await ai.models.generateContent({
                          model: modelToUse,
                          contents: requestContents,
                          config: {
                              imageConfig: imageConfig
                          }
                      });

                      let imageUrl = '';
                      if (response && response.candidates && response.candidates[0].content.parts) {
                          for (const part of response.candidates[0].content.parts) {
                              if (part.inlineData) {
                                  imageUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
                                  break;
                              }
                          }
                      }

                      if (imageUrl) {
                          const newImg: GeneratedImage = {
                              id: Date.now().toString() + i,
                              url: imageUrl,
                              prompt: prompt,
                              mode: state.mode,
                              category: state.category,
                              model: modelToUse,
                              aspectRatio: imageConfig.aspectRatio,
                              artStyle: state.artStyle
                          };
                          updateState(prev => ({
                              generatedImages: [...prev.generatedImages, newImg],
                              completedCount: prev.completedCount + 1
                          }));
                      }
                  }
              }
          }

      } catch (error) {
          console.error("Generation failed", error);
          alert("Generation failed. Please try a different model or prompt.");
      } finally {
          updateState({ isGenerating: false, generationStatus: 'Done' });
      }
  };

  // --- Icon Adjuster ---
  const handleIconUpload = (files: FileList) => {
      const newItems: IconItem[] = Array.from(files).map(file => ({
          id: Date.now().toString() + Math.random(),
          file,
          src: URL.createObjectURL(file),
          x: 0, y: 0, scale: 1,
          originalWidth: 512, originalHeight: 512
      }));

      newItems.forEach(item => {
          const img = new Image();
          img.onload = () => {
              item.originalWidth = img.naturalWidth;
              item.originalHeight = img.naturalHeight;
          };
          img.src = item.src;
      });

      updateState(prev => ({
          iconAdjusterData: {
              ...prev.iconAdjusterData,
              items: [...prev.iconAdjusterData.items, ...newItems]
          }
      }));
  };

  const updateIconAdjusterData = (updates: Partial<IconAdjusterData>) => {
      updateState(prev => ({
          iconAdjusterData: { ...prev.iconAdjusterData, ...updates }
      }));
  };

  const updateIconItem = (idOrIds: string | string[], updates: Partial<IconItem>) => {
      const ids = Array.isArray(idOrIds) ? idOrIds : [idOrIds];
      updateState(prev => ({
          iconAdjusterData: {
              ...prev.iconAdjusterData,
              items: prev.iconAdjusterData.items.map(item => ids.includes(item.id) ? { ...item, ...updates } : item)
          }
      }));
  };

  // --- BG Remover ---
  const updateBgRemoverData = (updates: Partial<BgRemoverData>) => {
      updateState(prev => ({
          bgRemoverData: { ...prev.bgRemoverData, ...updates }
      }));
  };

  // --- Image Editor ---
  const updateImageEditorData = (updates: Partial<ImageEditorData>) => {
      updateState(prev => ({
          imageEditorData: { ...prev.imageEditorData, ...updates }
      }));
  };

  // --- Tool Integration ---
  const handleSendToTool = (image: GeneratedImage, tool: 'icon_adjuster' | 'bg_remover' | 'image_editor', action?: 'new' | 'add') => {
      if (tool === 'icon_adjuster') {
          fetch(image.url).then(res => res.blob()).then(blob => {
              const file = new File([blob], `generated-${image.id}.png`, { type: 'image/png' });
              const newItem: IconItem = {
                  id: Date.now().toString(),
                  file,
                  src: image.url,
                  x: 0, y: 0, scale: 1,
                  originalWidth: 1024, originalHeight: 1024
              };
              updateState(prev => ({
                  mode: 'tools',
                  activeTool: 'icon_adjuster',
                  iconAdjusterData: { ...prev.iconAdjusterData, items: [...prev.iconAdjusterData.items, newItem] },
                  selectedImage: null
              }));
          });
      } else if (tool === 'bg_remover') {
          updateState({
              mode: 'tools',
              activeTool: 'bg_remover',
              bgRemoverData: { ...state.bgRemoverData, imageSrc: image.url, history: [], historyIndex: -1 },
              selectedImage: null
          });
      } else if (tool === 'image_editor') {
          fetch(image.url).then(res => res.blob()).then(blob => {
             const url = URL.createObjectURL(blob);
             const newLayer: EditorLayer = {
                 id: Date.now().toString(),
                 name: 'Imported Image',
                 type: 'image',
                 visible: true, locked: false, opacity: 100,
                 x: state.imageEditorData.canvasWidth/2, y: state.imageEditorData.canvasHeight/2,
                 width: 400, height: 400, rotation: 0,
                 src: url,
                 filters: { brightness: 100, contrast: 100, saturation: 100, blur: 0, hue: 0, sepia: 0, grayscale: 0 }
             };

             let newLayers = [...state.imageEditorData.layers];
             if (action === 'new') {
                 newLayers = [newLayer];
             } else {
                 newLayers.push(newLayer);
             }

             updateState({
                 mode: 'tools',
                 activeTool: 'image_editor',
                 imageEditorData: { ...state.imageEditorData, layers: newLayers },
                 selectedImage: null
             });
          });
      }
  };

  const handleSendRawImageToTool = (dataUrl: string, tool: 'icon_adjuster' | 'image_editor', action?: 'new' | 'add') => {
      if (tool === 'icon_adjuster') {
          fetch(dataUrl).then(res => res.blob()).then(blob => {
              const file = new File([blob], `processed.png`, { type: 'image/png' });
              const newItem: IconItem = {
                  id: Date.now().toString(),
                  file,
                  src: dataUrl,
                  x: 0, y: 0, scale: 1,
                  originalWidth: 1024, originalHeight: 1024
              };
              updateState(prev => ({
                  activeTool: 'icon_adjuster',
                  iconAdjusterData: { ...prev.iconAdjusterData, items: [...prev.iconAdjusterData.items, newItem] }
              }));
          });
      } else if (tool === 'image_editor') {
          const newLayer: EditorLayer = {
              id: Date.now().toString(),
              name: 'Processed Image',
              type: 'image',
              visible: true, locked: false, opacity: 100,
              x: state.imageEditorData.canvasWidth/2, y: state.imageEditorData.canvasHeight/2,
              width: 400, height: 400, rotation: 0,
              src: dataUrl,
              filters: { brightness: 100, contrast: 100, saturation: 100, blur: 0, hue: 0, sepia: 0, grayscale: 0 }
          };

          let newLayers = [...state.imageEditorData.layers];
          if (action === 'new') {
              newLayers = [newLayer];
          } else {
              newLayers.push(newLayer);
          }

          updateState(prev => ({
              activeTool: 'image_editor',
              imageEditorData: { ...prev.imageEditorData, layers: newLayers }
          }));
      }
  };

  return {
    state,
    activePopover,
    setActivePopover,
    fileInputRef,
    autoFillInputRef,
    hairRefInputRef,
    latestImageRef,
    canvasRef,
    updateState,
    handleFileUpload,
    handleDrop,
    clearReferenceImage,
    updateCharacterData,
    updateEnvironmentData,
    updateGamePropsData,
    updateUserInterfaceData,
    updateUIAssetData,
    updateIconDesignData,
    updateVariantData,
    updateSoundEffectData,
    handleGeneratePalette,
    updateCreatureMix,
    addCreatureMix,
    removeCreatureMix,
    updateCreatureAdvanced,
    handleTextureGridUpdate,
    updateTextureSlot,
    randomizeSlot,
    handleAutoFillClick,
    onAutoFillFileChange,
    handleGenerate,
    handleAITextureGenerate,
    handleSaveJSON,
    handleLoadJSON,
    handleIconUpload,
    updateIconAdjusterData,
    updateIconItem,
    updateBgRemoverData,
    updateImageEditorData,
    handleSendToTool,
    handleSendRawImageToTool,
    updateEditState,
    handleForceAngle,
    handleVariantHue,
    handleTextureScan
  };
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppState, TextureSlot } from '../../types';
import { TRANSLATIONS } from '../../translations';
import { UploadIcon, DeleteIcon, PlusIcon, LoadingSpinner, SparklesIcon, LockIcon, UnlockIcon, SaveIcon, FileIcon, ResetIcon } from '../../components/Icons';
import { randomizeHue, rgbToHex, hexToHSL, hslToHex } from '../../utils/colorMath';

interface Props {
  state: AppState;
  handleTextureGridUpdate: (rows: number, cols: number) => void;
  updateTextureSlot: (id: string, updates: Partial<TextureSlot>) => void;
  randomizeSlot: (id: string) => void;
  handleSaveTexture: () => void;
  canvasRef: React.RefObject<HTMLCanvasElement>;
  updateState: (updates: Partial<AppState> | ((prev: AppState) => Partial<AppState>)) => void;
  handleAITextureGenerate: (mode: 'single' | 'all') => void;
  handleSaveJSON: () => void;
  handleLoadJSON: (e: React.ChangeEvent<HTMLInputElement>) => void;
}

const TextureGenerator: React.FC<Props> = ({ state, handleTextureGridUpdate, updateTextureSlot, randomizeSlot, handleSaveTexture, canvasRef, updateState, handleAITextureGenerate, handleSaveJSON, handleLoadJSON }) => {
  const td = state.textureGeneratorData;
  const t = TRANSLATIONS[state.language];
  const selectedSlot = td.slots.find(s => s.id === td.selectedSlotId);
  const [draggingId, setDraggingId] = useState<string | null>(null);
  const [scanPadding, setScanPadding] = useState(10);
  const [forceAngle, setForceAngle] = useState(90);

  // Color Adjustment State
  const [adjustTarget, setAdjustTarget] = useState<'selected' | 'all'>('selected');
  const [hueAdj, setHueAdj] = useState(0);
  const [satAdj, setSatAdj] = useState(0);
  const [briAdj, setBriAdj] = useState(0);

  const scanInputRef = useRef<HTMLInputElement>(null);

  // Helper to calculate display color (Real-time)
  const getDisplayColors = useCallback((slot: TextureSlot) => {
      const isTarget = adjustTarget === 'all' || (adjustTarget === 'selected' && slot.id === td.selectedSlotId);

      // If no adjustment needed or locked
      if (!isTarget || slot.locked || (hueAdj === 0 && satAdj === 0 && briAdj === 0)) {
          return slot.colors;
      }

      return slot.colors.map(hex => {
          const { h, s, l } = hexToHSL(hex);

          // Adjust Hue
          let newH = (h + hueAdj) % 360;
          if (newH < 0) newH += 360;

          // Adjust Saturation
          let newS = Math.max(0, Math.min(1, s + (satAdj / 100)));

          // Adjust Brightness (Lightness)
          let newL = Math.max(0, Math.min(1, l + (briAdj / 100)));

          return hslToHex(newH, newS, newL);
      });
  }, [adjustTarget, hueAdj, satAdj, briAdj, td.selectedSlotId]);

  // --- Rendering Logic for Export ---
  useEffect(() => {
      const canvas = canvasRef.current;
      if (!canvas) return;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      const width = 1024;
      const height = 1024;
      canvas.width = width;
      canvas.height = height;

      // Fill background
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, width, height);

      td.slots.forEach((slot, index) => {
          if (index >= td.rows * td.cols) return;

          const col = index % td.cols;
          const row = Math.floor(index / td.cols);

          // Integer pixel alignment to prevent gaps (Seamless)
          const x1 = Math.floor(col * width / td.cols);
          const x2 = Math.floor((col + 1) * width / td.cols);
          const y1 = Math.floor(row * height / td.rows);
          const y2 = Math.floor((row + 1) * height / td.rows);

          const cellW = x2 - x1;
          const cellH = y2 - y1;

          const cx = x1 + cellW / 2;
          const cy = y1 + cellH / 2;

          ctx.save();
          // Clip to cell area
          ctx.beginPath();
          ctx.rect(x1, y1, cellW, cellH);
          ctx.clip();

          // Get Real-time colors
          const displayColors = getDisplayColors(slot);

          if (slot.type === 'solid') {
              ctx.fillStyle = displayColors[0] || '#ffffff';
              ctx.fillRect(x1, y1, cellW, cellH);
          } else {
              // Gradient Drawing Logic
              const angle = slot.angle || 0;
              const rad = (angle * Math.PI) / 180;

              // Determine gradient line
              // Calculate diagonal to ensure full coverage
              const dist = Math.sqrt(cellW * cellW + cellH * cellH) / 2;

              const dx = Math.sin(rad);
              const dy = -Math.cos(rad);

              // Start and End points relative to center
              const gx1 = cx - dx * dist;
              const gy1 = cy - dy * dist;
              const gx2 = cx + dx * dist;
              const gy2 = cy + dy * dist;

              const grd = ctx.createLinearGradient(gx1, gy1, gx2, gy2);

              displayColors.forEach((color, i) => {
                  // Calculate stop position 0-1
                  let stop = i / Math.max(1, displayColors.length - 1);
                  if (slot.stops && slot.stops[i] !== undefined) {
                      stop = slot.stops[i] / 100;
                  }
                  grd.addColorStop(Math.max(0, Math.min(1, stop)), color);
              });

              ctx.fillStyle = grd;
              ctx.fillRect(x1, y1, cellW, cellH);
          }
          ctx.restore();
      });

  }, [td, canvasRef, getDisplayColors]); // Re-render when data or adjustments change

  const updateSelectedSlot = (key: keyof TextureSlot, value: any) => {
      if (!selectedSlot) return;
      updateTextureSlot(selectedSlot.id, { [key]: value });
  };

  const handleDragStart = (e: React.DragEvent, id: string) => {
      const slot = td.slots.find(s => s.id === id);
      if (slot?.locked) {
          e.preventDefault();
          return;
      }
      setDraggingId(id);
      e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetId: string) => {
      e.preventDefault();
      if (!draggingId || draggingId === targetId) return;

      updateState((prev) => {
          const slots = [...prev.textureGeneratorData.slots];
          const sourceIndex = slots.findIndex(s => s.id === draggingId);
          const targetIndex = slots.findIndex(s => s.id === targetId);

          if (sourceIndex === -1 || targetIndex === -1) return prev;

          const temp = slots[sourceIndex];
          slots[sourceIndex] = slots[targetIndex];
          slots[targetIndex] = temp;

          return {
              ...prev,
              textureGeneratorData: {
                  ...prev.textureGeneratorData,
                  slots
              }
          };
      });
      setDraggingId(null);
  };

  const handleForceAngleAll = () => {
      updateState(prev => ({
          textureGeneratorData: {
              ...prev.textureGeneratorData,
              slots: prev.textureGeneratorData.slots.map(s => 
                  s.locked ? s : { ...s, angle: forceAngle }
              )
          }
      }));
  };

  const handleApplyColorAdjustments = () => {
      if (hueAdj === 0 && satAdj === 0 && briAdj === 0) return;

      updateState(prev => {
          const newSlots = prev.textureGeneratorData.slots.map(slot => {
              // Apply the calculated colors permanently
              const finalColors = getDisplayColors(slot);
              return { ...slot, colors: finalColors };
          });
          return { textureGeneratorData: { ...prev.textureGeneratorData, slots: newSlots } };
      });

      // Reset sliders after commit
      handleResetAdjustments();
  };

  const handleResetAdjustments = () => {
      setHueAdj(0);
      setSatAdj(0);
      setBriAdj(0);
  };

  const variantHue = () => {
      if(selectedSlot) {
          const newColors = selectedSlot.colors.map(c => randomizeHue(c));
          updateSelectedSlot('colors', newColors);
      }
  };

  const handleScanImport = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (evt) => {
          const img = new Image();
          img.onload = () => {
              const canvas = document.createElement('canvas');
              canvas.width = img.width;
              canvas.height = img.height;
              const ctx = canvas.getContext('2d');
              if (!ctx) return;
              ctx.drawImage(img, 0, 0);

              const rows = td.rows;
              const cols = td.cols;
              const slotW = img.width / cols;
              const slotH = img.height / rows;

              // We need to update all slots at once
              updateState(prev => {
                  const newSlots = prev.textureGeneratorData.slots.map((slot, index) => {
                      // Check if index is within grid range
                      if (index >= rows * cols) return slot;
                      if (slot.locked) return slot;

                      const r = Math.floor(index / cols);
                      const c = index % cols;
                      const x = c * slotW;
                      const y = r * slotH;

                      // Sample Logic
                      // Clamp padding
                      const safePadding = Math.min(scanPadding, slotH/2 - 1);

                      // Top Sample
                      const p1 = ctx.getImageData(x + slotW/2, y + safePadding, 1, 1).data;
                      const hex1 = rgbToHex(p1[0], p1[1], p1[2]);

                      // Bottom Sample
                      const p2 = ctx.getImageData(x + slotW/2, y + slotH - safePadding, 1, 1).data;
                      const hex2 = rgbToHex(p2[0], p2[1], p2[2]);

                      return {
                          ...slot,
                          type: 'gradient' as const,
                          colors: [hex1, hex2],
                          angle: 90,
                          stops: [0, 100]
                      };
                  });
                  return { textureGeneratorData: { ...prev.textureGeneratorData, slots: newSlots } };
              });
          };
          img.src = evt.target?.result as string;
      };
      reader.readAsDataURL(file);
      // Reset input
      e.target.value = '';
  };

  return (
    <div className="flex-1 flex flex-col md:flex-row h-full overflow-hidden animate-fade-in-up">
      <div className="w-full md:w-80 bg-zinc-900/80 border-r border-zinc-800 p-6 overflow-y-auto custom-scrollbar flex flex-col gap-6">
          <h2 className="text-xl font-bold text-white flex items-center gap-2">
              <span className="text-teal-400">🎨</span> {t.textureGen.title}
          </h2>

          <div className="space-y-3">
              <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-wider">{t.textureGen.gridSize}</h4>
              <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1">
                      <label className="text-[10px] text-zinc-400">{t.textureGen.rows}</label>
                      <input type="number" min="1" max="10" value={td.rows} onChange={(e) => handleTextureGridUpdate(parseInt(e.target.value), td.cols)} className="w-full bg-zinc-950 border border-zinc-700 rounded-lg p-2 text-sm text-center" />
                  </div>
                  <div className="space-y-1">
                      <label className="text-[10px] text-zinc-400">{t.textureGen.cols}</label>
                      <input type="number" min="1" max="10" value={td.cols} onChange={(e) => handleTextureGridUpdate(td.rows, parseInt(e.target.value))} className="w-full bg-zinc-950 border border-zinc-700 rounded-lg p-2 text-sm text-center" />
                  </div>
              </div>
          </div>

          <div className="h-px bg-zinc-800" />

          {/* Global Settings */}
          <div className="space-y-3">
              <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-wider">Global Settings</h4>
              <div className="flex items-center gap-2 bg-zinc-950 p-2 rounded-lg border border-zinc-800">
                  <div className="flex items-center gap-1 flex-1">
                      <span className="text-[10px] text-zinc-400 whitespace-nowrap">Force Angle</span>
                      <input 
                          type="number" 
                          value={forceAngle} 
                          onChange={(e) => setForceAngle(parseInt(e.target.value))} 
                          className="w-full bg-zinc-900 border border-zinc-700 rounded px-1 py-0.5 text-xs text-center text-white focus:border-teal-500 outline-none"
                      />
                      <span className="text-[10px] text-zinc-500">°</span>
                  </div>
                  <button onClick={handleForceAngleAll} className="px-3 py-1 bg-zinc-800 hover:bg-zinc-700 text-zinc-300 border border-zinc-700 rounded text-xs font-medium transition">
                      Apply All
                  </button>
              </div>
          </div>

          <div className="h-px bg-zinc-800" />

          {/* Color Adjustments */}
          <div className="space-y-3">
              <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-wider">Color Adjustments</h4>

              <div className="flex bg-zinc-950 p-1 rounded-lg border border-zinc-800 mb-2">
                  <button 
                      onClick={() => setAdjustTarget('selected')} 
                      className={`flex-1 py-1.5 text-[10px] font-bold rounded transition ${adjustTarget === 'selected' ? 'bg-zinc-700 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
                  >
                      Selected Slot
                  </button>
                  <button 
                      onClick={() => setAdjustTarget('all')} 
                      className={`flex-1 py-1.5 text-[10px] font-bold rounded transition ${adjustTarget === 'all' ? 'bg-zinc-700 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
                  >
                      All Slots
                  </button>
              </div>

              <div className="space-y-2">
                  <div className="flex items-center gap-2">
                      <span className="text-[10px] text-zinc-400 w-12">Hue</span>
                      <input type="range" min="-180" max="180" value={hueAdj} onChange={(e) => setHueAdj(parseInt(e.target.value))} className="flex-1 h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-teal-500" />
                      <span className="text-[10px] text-zinc-500 w-8 text-right">{hueAdj}°</span>
                  </div>
                  <div className="flex items-center gap-2">
                      <span className="text-[10px] text-zinc-400 w-12">Sat</span>
                      <input type="range" min="-100" max="100" value={satAdj} onChange={(e) => setSatAdj(parseInt(e.target.value))} className="flex-1 h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-teal-500" />
                      <span className="text-[10px] text-zinc-500 w-8 text-right">{satAdj}</span>
                  </div>
                  <div className="flex items-center gap-2">
                      <span className="text-[10px] text-zinc-400 w-12">Bright</span>
                      <input type="range" min="-100" max="100" value={briAdj} onChange={(e) => setBriAdj(parseInt(e.target.value))} className="flex-1 h-1 bg-zinc-800 rounded appearance-none cursor-pointer accent-teal-500" />
                      <span className="text-[10px] text-zinc-500 w-8 text-right">{briAdj}</span>
                  </div>
              </div>

              <div className="flex gap-2">
                  <button 
                      onClick={handleResetAdjustments}
                      className="px-3 py-2 bg-zinc-800 hover:bg-zinc-700 text-zinc-400 hover:text-white rounded-lg transition"
                      title="Reset sliders"
                  >
                      <ResetIcon className="w-4 h-4" />
                  </button>
                  <button 
                      onClick={handleApplyColorAdjustments} 
                      disabled={hueAdj === 0 && satAdj === 0 && briAdj === 0}
                      className={`flex-1 py-2 rounded-lg text-xs font-bold transition ${hueAdj === 0 && satAdj === 0 && briAdj === 0 ? 'bg-zinc-900 text-zinc-600 cursor-not-allowed' : 'bg-teal-600 hover:bg-teal-500 text-white shadow-lg'}`}
                  >
                      Apply Adjustments
                  </button>
              </div>
          </div>

          <div className="h-px bg-zinc-800" />

          {/* Scan Section */}
          <div className="space-y-3">
              <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-wider">Scan & Import</h4>
              <div className="flex items-center gap-2">
                  <div className="space-y-1 flex-1">
                      <label className="text-[10px] text-zinc-400">Padding (px)</label>
                      <input type="number" min="0" max="100" value={scanPadding} onChange={(e) => setScanPadding(parseInt(e.target.value))} className="w-full bg-zinc-950 border border-zinc-700 rounded-lg p-2 text-xs" />
                  </div>
                  <button onClick={() => scanInputRef.current?.click()} className="flex-1 py-2 bg-zinc-800 hover:bg-zinc-700 text-zinc-300 rounded-lg text-xs font-bold transition flex flex-col items-center justify-center gap-1 h-full mt-auto">
                      <UploadIcon className="w-4 h-4" /> Scan Photo
                  </button>
                  <input type="file" ref={scanInputRef} accept="image/*" className="hidden" onChange={handleScanImport} />
              </div>
              <p className="text-[9px] text-zinc-600">Upload a texture grid image to auto-sample colors based on current grid size.</p>
          </div>

          <div className="h-px bg-zinc-800" />

          <div className="space-y-3">
               <h4 className="text-xs font-bold text-teal-400 uppercase tracking-wider flex items-center gap-1">✨ {t.textureGen.aiTitle}</h4>
               <textarea 
                  value={td.texturePrompt || ''}
                  onChange={(e) => updateState(prev => ({...prev, textureGeneratorData: { ...prev.textureGeneratorData, texturePrompt: e.target.value }}))}
                  placeholder={t.textureGen.promptPlaceholder}
                  className="w-full h-20 bg-zinc-950 border border-zinc-700 rounded-lg p-2 text-xs resize-none focus:border-teal-500 outline-none"
               />
               <div className="flex gap-2">
                   <button 
                      onClick={() => handleAITextureGenerate('single')}
                      disabled={state.isGenerating || !selectedSlot || selectedSlot.locked}
                      className={`flex-1 py-2 rounded-lg text-xs font-bold flex items-center justify-center gap-2 transition ${state.isGenerating || !selectedSlot || selectedSlot.locked ? 'bg-zinc-800 text-zinc-500' : 'bg-zinc-700 hover:bg-zinc-600 text-white shadow-md'}`}
                      title={selectedSlot?.locked ? t.textureGen.locked : ''}
                   >
                       {state.isGenerating ? <LoadingSpinner className="w-3 h-3" /> : <span className="text-lg">🎯</span>}
                       {t.textureGen.generateSlot}
                   </button>
                   <button 
                      onClick={() => handleAITextureGenerate('all')}
                      disabled={state.isGenerating}
                      className={`flex-1 py-2 rounded-lg text-xs font-bold flex items-center justify-center gap-2 transition ${state.isGenerating ? 'bg-zinc-800 text-zinc-500' : 'bg-gradient-to-r from-teal-600 to-emerald-600 text-white hover:scale-105 shadow-lg'}`}
                   >
                       {state.isGenerating ? <LoadingSpinner className="w-3 h-3" /> : <SparklesIcon className="w-3 h-3" />}
                       {t.textureGen.generateAll}
                   </button>
               </div>
          </div>

          <div className="h-px bg-zinc-800" />

          <div className="flex-1 space-y-4">
              <div className="flex items-center justify-between">
                  <h4 className="text-xs font-bold text-zinc-500 uppercase tracking-wider">{t.textureGen.slotSettings}</h4>
                  {selectedSlot && (
                      <button 
                        onClick={() => updateSelectedSlot('locked', !selectedSlot.locked)}
                        className={`text-xs flex items-center gap-1 px-2 py-1 rounded transition ${selectedSlot.locked ? 'bg-zinc-700 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
                        title={selectedSlot.locked ? t.textureGen.unlock : t.textureGen.lock}
                      >
                          {selectedSlot.locked ? <UnlockIcon className="w-3 h-3" /> : <LockIcon className="w-3 h-3" />}
                          <span className="hidden sm:inline">{selectedSlot.locked ? t.textureGen.unlock : t.textureGen.lock}</span>
                      </button>
                  )}
              </div>

              {selectedSlot ? (
                  <div className={`space-y-4 animate-fade-in ${selectedSlot.locked ? 'opacity-50 pointer-events-none grayscale' : ''}`}>
                      <div className="flex bg-zinc-950 rounded-lg p-1 border border-zinc-800">
                           <button onClick={() => updateSelectedSlot('type', 'solid')} className={`flex-1 py-1.5 text-xs rounded-md transition ${selectedSlot.type === 'solid' ? 'bg-zinc-700 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}>{t.textureGen.solid}</button>
                           <button onClick={() => updateSelectedSlot('type', 'gradient')} className={`flex-1 py-1.5 text-xs rounded-md transition ${selectedSlot.type === 'gradient' ? 'bg-zinc-700 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}>{t.textureGen.gradient}</button>
                      </div>

                      <div className="space-y-2">
                           <label className="text-xs text-zinc-400">{selectedSlot.type === 'solid' ? t.textureGen.color : t.textureGen.colors}</label>
                           <div className="flex flex-col gap-2">
                               {selectedSlot.colors.map((col, idx) => (
                                   <div key={idx} className="flex items-center gap-2 bg-zinc-950/50 p-1.5 rounded-lg border border-zinc-800/50">
                                       <input type="color" value={col} onChange={(e) => { const newColors = [...selectedSlot.colors]; newColors[idx] = e.target.value; updateSelectedSlot('colors', newColors); }} className="w-8 h-8 rounded bg-transparent cursor-pointer border border-zinc-700 shrink-0" />

                                       {selectedSlot.type === 'gradient' && (
                                           <div className="flex-1 flex flex-col justify-center px-1">
                                               <div className="flex justify-between text-[10px] text-zinc-500 mb-0.5">
                                                   <span>Pos</span>
                                                   <span>{selectedSlot.stops?.[idx] ?? 0}%</span>
                                               </div>
                                               <input 
                                                    type="range" 
                                                    min="0" 
                                                    max="100" 
                                                    value={selectedSlot.stops?.[idx] ?? (idx * (100 / (Math.max(1, selectedSlot.colors.length - 1))))} 
                                                    onChange={(e) => {
                                                        const currentStops = selectedSlot.stops || selectedSlot.colors.map((_, i) => i * (100 / (Math.max(1, selectedSlot.colors.length - 1))));
                                                        const newStops = [...currentStops];
                                                        newStops[idx] = parseInt(e.target.value);
                                                        updateTextureSlot(selectedSlot.id, { stops: newStops });
                                                    }}
                                                    className="w-full h-1 bg-zinc-700 rounded-lg appearance-none cursor-pointer accent-teal-500"
                                               />
                                           </div>
                                       )}

                                       {selectedSlot.type === 'gradient' && selectedSlot.colors.length > 2 && (
                                           <button onClick={() => {
                                                const newColors = selectedSlot.colors.filter((_, i) => i !== idx);
                                                const currentStops = selectedSlot.stops || selectedSlot.colors.map((_, i) => i * (100 / (Math.max(1, selectedSlot.colors.length - 1))));
                                                const newStops = currentStops.filter((_, i) => i !== idx);
                                                updateTextureSlot(selectedSlot.id, { colors: newColors, stops: newStops });
                                           }} className="p-1.5 text-zinc-600 hover:text-red-500 hover:bg-zinc-800 rounded transition shrink-0"><DeleteIcon className="w-3 h-3" /></button>
                                       )}
                                   </div>
                               ))}
                               {selectedSlot.type === 'gradient' && (
                                   <button onClick={() => {
                                       const newColors = [...selectedSlot.colors, '#ffffff'];
                                       const newStops = [...(selectedSlot.stops || []), 100];
                                       updateTextureSlot(selectedSlot.id, { colors: newColors, stops: newStops });
                                   }} className="w-full py-2 rounded border border-dashed border-zinc-700 flex items-center justify-center text-zinc-500 hover:text-white hover:border-zinc-500 hover:bg-zinc-800 transition"><PlusIcon className="w-4 h-4 mr-1" /> Add Color Stop</button>
                               )}
                           </div>
                      </div>

                      {selectedSlot.type === 'gradient' && (
                           <div className="space-y-3 pt-2 border-t border-zinc-800">
                               <div className="flex justify-between items-center text-xs text-zinc-400">
                                   <span>{t.textureGen.angle}</span>
                                   <div className="flex items-center gap-1">
                                       <input 
                                            type="number" 
                                            value={selectedSlot.angle} 
                                            onChange={(e) => updateSelectedSlot('angle', Math.min(360, Math.max(0, parseInt(e.target.value) || 0)))}
                                            className="w-12 bg-zinc-950 border border-zinc-700 rounded px-1 py-0.5 text-right text-white focus:border-teal-500 outline-none"
                                       />
                                       <span>°</span>
                                   </div>
                               </div>

                               <input type="range" min="0" max="360" value={selectedSlot.angle} onChange={(e) => updateSelectedSlot('angle', parseInt(e.target.value))} className="w-full h-2 bg-zinc-800 rounded-lg appearance-none cursor-pointer accent-teal-500" />

                               <div className="flex gap-2">
                                   {[0, 90, 180, 270].map(deg => (
                                       <button 
                                            key={deg} 
                                            onClick={() => updateSelectedSlot('angle', deg)}
                                            className={`flex-1 py-1 text-[10px] rounded border transition ${selectedSlot.angle === deg ? 'bg-teal-500/20 text-teal-300 border-teal-500/50' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:bg-zinc-800 hover:text-zinc-300'}`}
                                       >
                                           {deg}°
                                       </button>
                                   ))}
                               </div>
                           </div>
                      )}

                      <div className="grid grid-cols-2 gap-2">
                          <button onClick={variantHue} className="w-full py-2 bg-purple-900/30 hover:bg-purple-900/50 text-purple-300 border border-purple-900/50 rounded-lg text-xs font-bold transition">Variant Color (Hue)</button>
                          <button onClick={() => randomizeSlot(selectedSlot.id)} className="w-full py-2 bg-zinc-800 hover:bg-zinc-700 text-zinc-300 rounded-lg text-xs font-bold transition">🎲 {t.textureGen.randomize}</button>
                      </div>
                  </div>
              ) : (
                  <p className="text-sm text-zinc-500 italic text-center py-8">{t.textureGen.selectSlot}</p>
              )}
          </div>

          <div className="grid grid-cols-2 gap-2">
               <button onClick={handleSaveJSON} className="py-2.5 bg-zinc-800 hover:bg-zinc-700 text-zinc-300 rounded-lg text-xs font-bold transition flex items-center justify-center gap-2">
                   <SaveIcon className="w-4 h-4" /> {t.textureGen.saveJson}
               </button>
               <label className="py-2.5 bg-zinc-800 hover:bg-zinc-700 text-zinc-300 rounded-lg text-xs font-bold transition flex items-center justify-center gap-2 cursor-pointer">
                   <FileIcon className="w-4 h-4" /> {t.textureGen.loadJson}
                   <input type="file" className="hidden" accept=".json" onChange={handleLoadJSON} />
               </label>
          </div>

          <button onClick={handleSaveTexture} className="w-full py-3 bg-teal-600 hover:bg-teal-500 text-white rounded-xl font-bold shadow-lg shadow-teal-900/20 transition-transform active:scale-95 flex items-center justify-center gap-2">
              <UploadIcon className="w-4 h-4 rotate-180" /> {t.textureGen.export}
          </button>
          <div className="hidden"><canvas ref={canvasRef} width={1024} height={1024} /></div>
      </div>

      <div className="flex-1 bg-zinc-950 p-4 md:p-8 flex items-center justify-center overflow-auto bg-[url('https://grainy-gradients.vercel.app/noise.svg')] bg-opacity-5">
           <div className="aspect-square bg-white shadow-2xl relative grid" style={{ width: 'min(100%, 600px)', gridTemplateColumns: `repeat(${td.cols}, 1fr)`, gridTemplateRows: `repeat(${td.rows}, 1fr)` }}>
               {td.slots.map((slot) => {
                   const displayColors = getDisplayColors(slot);

                   let background = displayColors[0];
                   if (slot.type === 'gradient') {
                       const stops = slot.stops || displayColors.map((_, i) => i * (100 / (Math.max(1, displayColors.length - 1))));
                       const gradientParts = displayColors.map((col, i) => `${col} ${stops[i]}%`).join(', ');
                       background = `linear-gradient(${slot.angle}deg, ${gradientParts})`;
                   }

                   return (
                       <div 
                          key={slot.id}
                          draggable={!slot.locked}
                          onDragStart={(e) => handleDragStart(e, slot.id)}
                          onDragOver={handleDragOver}
                          onDrop={(e) => handleDrop(e, slot.id)}
                          onClick={() => updateState((prev) => ({...prev, textureGeneratorData: { ...prev.textureGeneratorData, selectedSlotId: slot.id }}))}
                          className={`
                            cursor-pointer border transition-all duration-200 relative
                            ${td.selectedSlotId === slot.id ? 'border-teal-500 border-2 z-20 shadow-lg scale-105' : 'border-transparent hover:border-white/50 hover:z-10 hover:shadow-xl'}
                            ${draggingId === slot.id ? 'opacity-50' : ''}
                            ${slot.locked ? 'cursor-not-allowed' : 'cursor-grab active:cursor-grabbing'}
                          `}
                          style={{ background }}
                       >
                           {slot.locked && (
                               <div className="absolute top-1 right-1 bg-black/50 rounded p-0.5">
                                   <LockIcon className="w-3 h-3 text-white/80" />
                               </div>
                           )}
                       </div>
                   );
               })}
           </div>
      </div>
    </div>
  );
};
export default TextureGenerator;

export type Language = 'en' | 'th';

export interface IconOverlay {
  src: string;
  x: number;
  y: number;
  scale: number;
  rotation: number;
}

export interface IconItem {
  id: string;
  file: File;
  src: string; // Object URL
  x: number;
  y: number;
  scale: number;
  originalWidth: number;
  originalHeight: number;
  overlay?: IconOverlay;
}

export type IconCommandMode = 'one' | 'multi' | 'all';

export interface IconAdjusterData {
  items: IconItem[];
  selectedItemIds: string[]; // Array for multi-select
  commandMode: IconCommandMode;
  canvasWidth: number;
  canvasHeight: number;
  background: 'transparent' | 'white' | 'black' | 'custom';
  backgroundColor: string;
  strokeEnabled: boolean;
  strokeColor: string;
  strokeThickness: number;
  strokeSmoothness: number;
  strokeBlur: number;
  moveStep: number;
  scaleStep: number;
  fitPadding: number;
  cropThreshold: number; // 0-255
  gridColumns: number; // New: Grid preview size
}

export type CoreMode = 'idea' | 'variant' | 'edit' | 'render' | 'tools';
export type ToolMode = 'texture_grid' | 'icon_adjuster' | 'bg_remover' | 'image_editor';
export type Category = 'character' | 'creatures' | 'environment' | 'game_props' | 'user_interface' | 'ui_asset' | 'icon_design' | 'logo_design';
export type ModelType = 'gemini-2.5-flash-image' | 'gemini-2.5-pro-preview' | 'gemini-3-pro-image-preview' | 'gemini-2.5-flash';
export type AspectRatio = '1:1' | '16:9' | '9:16' | '4:3' | '3:4';
export type ImageSize = '1K' | '2K' | '4K';
export type ArtStyle = 'none' | 'realistic' | 'anime' | 'digital_art' | '3d_render' | 'pixel_art' | 'oil_painting' | 'watercolor' | 'sketch' | 'cyberpunk' | 'fantasy' | 'scifi' | 'cartoon' | 'flat_design' | 'isometric' | 'low_poly' | 'claymation' | 'cel_shaded' | 'zen_brush' | 'japanese_trad' | 'manga' | 'manhwa' | 'webtoon_low' | 'webtoon_high' | 'concept_art' | 'middle_age' | 'child_scribble' | 'sculpture';
export type ItemCount = 1 | 2 | 4 | 8;
export type HarmonyType = 'primary' | 'analogous' | 'complementary' | 'split_complementary' | 'double_split_complementary' | 'triadic' | 'square' | 'tetradic';

export interface SelectOption {
  value: string;
  label: { en: string; th: string };
}

export interface GeneratedImage {
  id: string;
  url: string;
  prompt: string;
  mode: CoreMode;
  category: Category;
  model: string;
  aspectRatio: string;
  artStyle: string;
}

export interface CharacterData {
  name: string;
  gender: string;
  age: number;
  height: number;
  weight: number;
  species: string;
  customSpecies: string;
  bodyBuild: string;
  customBodyBuild: string;
  hairStyle: string;
  customHairStyle: string;
  hairReferenceImage: string | null;
  hairColor: string;
  eyeColor: string;
  skinTone: string;
  attireMode: 'preset' | 'detailed';
  clothingStyle: string;
  headwear: string;
  eyewear: string;
  torso: string;
  bottom: string;
  footwear: string;
  gloves: string;
  accessories: string;
}

export interface CreatureMix {
  id: string;
  name: string;
  percentage: number;
  bodyParts?: string;
}

export interface CreatureAdvancedData {
  primaryShape: string;
  exaggeratedPart: string;
  scaleComparison: string;
  habitat: string;
  diet: string;
  evolutionaryTrait: string;
  skeletalStructure: string;
  locomotionMode: string;
  appendages: string;
  skinType: string;
  dominantColor: string;
  vfxPoints: string;
  clothing: string;
  accessories: string;
  weaponry: string;
  disposition: string;
}

export interface EnvironmentData {
  locationName: string;
  history: string;
  inhabitants: string;
  civilizationLevel: string;
  mood: string;
  timeOfDay: string;
  weather: string;
  lighting: string;
  cameraView: string;
  focalPoint: string;
  scale: string;
}

export interface GamePropsData {
  category: string;
  subCategory: string;
  theme: string;
  materials: string[];
  primaryColor: string;
  shape: string;
  age: number;
  damage: string[];
  cameraView: string;
  lighting: string;
  backgroundColor: string;
  influence: number;
  structureWeight: number;
  styleWeight: number;
  strokeEnabled: boolean;
  strokeColor: string;
  strokeThickness: number;
  shadowEnabled: boolean;
  shadowColor: string;
  shadowOpacity: number;
  shadowDistance: number;
  shadowAngle: number;
  glowEnabled: boolean;
  glowColor: string;
  glowIntensity: number;
}

export interface UserInterfaceData {
  screenType: string;
  uiStyle: string;
  materials: string[];
  shape: string;
  platform: string;
  techTags: string[];
}

export interface UIAssetData {
  assetType: string;
  theme: string;
  colorTheme: string;
  useColorTheme: boolean;
  backgroundColor: string;
  assetTags: string[];
  matchShape: number;
  matchColor: number;
  matchStyle: number;
  matchTexture: number;
}

export interface IconDesignData {
  iconStyle: string;
  backgroundShape: string;
  fillColorType: 'solid' | 'gradient';
  fillColor: string;
  fillGradientStart: string;
  fillGradientEnd: string;
  bgColorType: 'solid' | 'gradient';
  bgColor: string;
  bgGradientStart: string;
  bgGradientEnd: string;
  cameraView: string;
  alignment: string;
  innerIconShape: string;
}

export interface VariantData {
  matchShape: number;
  matchColor: number;
  matchStyle: number;
  matchTexture: number;
  colorStrategy: string;
  useColorHarmony: boolean;
  harmonyType: HarmonyType;
  baseColor: string;
  autoHarmony: boolean;
  generatedPalette: string[];
}

export interface TextureSlot {
  id: string;
  type: 'solid' | 'gradient';
  colors: string[];
  angle: number;
  stops?: number[];
  locked?: boolean;
}

export interface BgRemoverData {
  imageSrc: string | null;
  history: ImageData[];
  historyIndex: number;
  selectionMode: 'add' | 'remove';
  tolerance: number;
  brushSize: number;
  feather: number;
  expand: number;
  previewBg: string;
}

export interface EditorLayer {
  id: string;
  name: string;
  type: 'image' | 'solid' | 'shape' | 'frame';
  visible: boolean;
  locked: boolean;
  opacity: number;
  x: number;
  y: number;
  width: number;
  height: number;
  rotation: number;
  src?: string;
  color?: string; // for solid or shape
  fillType?: 'solid' | 'gradient' | 'none';
  gradientStops?: string[];
  gradientStopPositions?: number[];
  gradientAngle?: number;
  strokeColor?: string;
  strokeWidth?: number;
  shapeType?: string; // from SHAPE_LIBRARY
  cornerRadius?: number;
  cornerRadii?: number[];
  frameImage?: {
      src: string;
      x: number;
      y: number;
      scale: number;
      rotation: number;
      originalWidth: number;
      originalHeight: number;
  } | null;
  filters?: {
      brightness: number;
      contrast: number;
      saturation: number;
      blur: number;
      hue: number;
      sepia: number;
      grayscale: number;
  };
  tintColor?: string | null;
  groupId?: string | null;
}

export interface ImageEditorData {
  canvasWidth: number;
  canvasHeight: number;
  layers: EditorLayer[];
  selectedLayerIds: string[];
  zoom: number;
  activeTool: 'move' | 'crop' | 'select';
  lockAspectRatio?: boolean;
  viewX?: number;
  viewY?: number;
  cropRect?: { x: number, y: number, w: number, h: number };
  fitPadding?: number;
}

export type EditModelMode = 'fast' | 'pro';

export interface MaskPath {
    points: {x:number, y:number}[];
    brushSize: number;
    isEraser: boolean;
}

export interface FixData {
    maskHistory: MaskPath[];
    brushSize: number;
    selectionFeather: number;
    maskOpacity: number;
    maskColor: string;
    prompt: string;
}

export interface ExpandData {
    resizeFactor: number;
    placementX: number;
    placementY: number;
    prompt: string;
}

export interface UpscaleData {
    scale: '2k' | '4k';
    creativity: number;
}

export interface EditState {
    activeMode: EditModelMode;
    prompts: {
        fast: string;
        pro: string;
    };
    settings: {
        fast: {
            aspectRatio: AspectRatio;
            batchSize: number;
        };
        pro: {
            aspectRatio: AspectRatio;
            batchSize: number;
            resolution: ImageSize;
        };
    };
    fixData: FixData;
    expandData: ExpandData;
    upscaleData: UpscaleData;
}

export interface Tool {
  id: string;
  title: string;
  description?: string;
  url: string;
  iconType: 'language' | 'roblox' | 'planet';
}

export interface AppState {
  language: Language;
  selectedModel: ModelType;
  mode: CoreMode;
  category: Category;
  prompt: string;
  negativePrompt: string;
  referenceImage: string | null;
  isGenerating: boolean;
  generatedImages: GeneratedImage[];
  selectedImage: GeneratedImage | null;
  batchSize: number;
  aspectRatio: AspectRatio;
  showRenderSettings: boolean;
  itemCount: ItemCount;
  imageSize: ImageSize;
  isSidebarExpanded: boolean;
  artStyle: ArtStyle;
  completedCount: number;
  totalBatchCount: number;
  generationStatus: string;

  // Data Sections
  characterData: CharacterData;
  creatureMixes: CreatureMix[];
  creatureAdvanced: CreatureAdvancedData;
  showCreatureAdvanced: boolean;
  environmentData: EnvironmentData;
  gamePropsData: GamePropsData;
  userInterfaceData: UserInterfaceData;
  uiAssetData: UIAssetData;
  iconDesignData: IconDesignData;
  variantData: VariantData;

  isAutoFilling: boolean;

  // Edit Mode
  editState: EditState;

  // Gallery
  galleryViewMode: 'featured' | 'grid5' | 'grid3' | 'grid2';
  galleryActiveImageId: string | null;

  // Tools
  activeTool: ToolMode | 'texture_grid';
  textureGeneratorData: {
      rows: number;
      cols: number;
      slots: TextureSlot[];
      selectedSlotId: string | null;
      texturePrompt?: string;
  };

  iconAdjusterData: IconAdjusterData;
  bgRemoverData: BgRemoverData;
  imageEditorData: ImageEditorData;
}

