import React from 'react';
import { AppState, Category } from '../../types';
import { TRANSLATIONS } from '../../translations';
import { ChevronLeftIcon, ChevronRightIcon, CharacterIcon, CreaturesIcon, EnvironmentIconReal, GamePropsIcon, UserInterfaceIcon, UIAssetIcon, IconDesignIcon, LogoIcon, MagicWandIcon, PhotoEditIcon } from '../Icons';

const CATEGORY_ICONS: Record<Category, React.FC<any>> = {
  character: CharacterIcon,
  creatures: CreaturesIcon,
  environment: EnvironmentIconReal,
  game_props: GamePropsIcon,
  user_interface: UserInterfaceIcon,
  ui_asset: UIAssetIcon,
  icon_design: IconDesignIcon,
  logo_design: LogoIcon,
};

interface Props {
  state: AppState;
  updateState: (updates: Partial<AppState>) => void;
}

const Sidebar: React.FC<Props> = ({ state, updateState }) => {
  const t = TRANSLATIONS[state.language];
  const toggleSidebar = () => updateState({ isSidebarExpanded: !state.isSidebarExpanded });

  return (
    <aside className={`relative z-20 flex flex-col border-r border-zinc-800/50 bg-zinc-950/50 backdrop-blur-xl transition-all duration-300 ease-in-out ${state.isSidebarExpanded ? 'w-16 md:w-64' : 'w-16 md:w-20'}`}>
      <div className="p-4 md:p-6 flex justify-between items-center">
        <div className={`overflow-hidden transition-all duration-300 ${state.isSidebarExpanded ? 'md:w-auto md:opacity-100' : 'md:w-0 md:opacity-0 hidden md:block'}`}>
          <h1 className="hidden md:block text-xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-purple-400 whitespace-nowrap">{t.title}</h1>
          <span className="hidden md:block text-xs font-bold text-zinc-500 tracking-[0.3em] whitespace-nowrap">{state.mode === 'tools' ? 'TOOLBOX' : 'STUDIO'}</span>
        </div>

        <span className={`${state.isSidebarExpanded ? 'md:hidden' : ''} text-2xl font-black text-indigo-500 md:hidden`}>S</span>
        <span className={`${!state.isSidebarExpanded ? 'hidden md:block' : 'hidden'} text-2xl font-black text-indigo-500 mx-auto`}>S</span>

        <button onClick={toggleSidebar} className="hidden md:flex p-1.5 hover:bg-zinc-800 rounded-lg text-zinc-500 hover:text-white transition-colors ml-auto">
          {state.isSidebarExpanded ? <ChevronLeftIcon className="w-5 h-5" /> : <ChevronRightIcon className="w-5 h-5" />}
        </button>
      </div>

      <nav className="flex-1 flex flex-col gap-2 px-2 md:px-3 py-4 overflow-y-auto custom-scrollbar">
        {state.mode === 'idea' && (
            (Object.keys(t.categories) as Category[]).map((catKey) => {
            const label = t.categories[catKey];
            const Icon = CATEGORY_ICONS[catKey];
            const isActive = state.category === catKey;

            return (
                <button
                key={catKey}
                onClick={() => updateState({ category: catKey })}
                className={`group flex items-center gap-3 p-3 rounded-xl transition-all duration-300 relative ${isActive ? 'bg-zinc-100 text-zinc-950 shadow-lg' : 'text-zinc-400 hover:bg-zinc-800/50 hover:text-white'} ${state.isSidebarExpanded ? 'justify-center md:justify-start' : 'justify-center'}`}
                title={label}
                >
                <div className={`${isActive ? 'text-zinc-950' : 'text-zinc-500 group-hover:text-zinc-300'}`}><Icon className="w-6 h-6 shrink-0" /></div>
                <div className={`hidden md:flex flex-col items-start text-left overflow-hidden whitespace-nowrap transition-all duration-300 ${state.isSidebarExpanded ? 'w-auto opacity-100' : 'w-0 opacity-0'}`}><span className="text-sm font-semibold">{label}</span></div>
                {isActive && (<div className="absolute left-0 w-1 h-8 bg-zinc-950 rounded-r-full" />)}
                </button>
            );
            })
        )}

        {state.mode === 'tools' && (
            <>
            <button onClick={() => updateState({ activeTool: 'texture_grid' })} className={`group flex items-center gap-3 p-3 rounded-xl transition-all duration-300 relative ${state.activeTool === 'texture_grid' ? 'bg-teal-500/10 text-teal-400 border border-teal-500/20 shadow-lg' : 'text-zinc-400 hover:bg-zinc-800/50 hover:text-white'} ${state.isSidebarExpanded ? 'justify-center md:justify-start' : 'justify-center'}`}>
                <div className={`${state.activeTool === 'texture_grid' ? 'text-teal-400' : 'text-zinc-500 group-hover:text-zinc-300'}`}>
                    <div className="w-6 h-6 grid grid-cols-2 gap-0.5 opacity-80"><div className="bg-current rounded-[1px]"></div><div className="bg-current rounded-[1px] opacity-50"></div><div className="bg-current rounded-[1px] opacity-50"></div><div className="bg-current rounded-[1px]"></div></div>
                </div>
                <div className={`hidden md:flex flex-col items-start text-left overflow-hidden whitespace-nowrap transition-all duration-300 ${state.isSidebarExpanded ? 'w-auto opacity-100' : 'w-0 opacity-0'}`}><span className="text-sm font-semibold">Texture Generator</span></div>
            </button>

            <button onClick={() => updateState({ activeTool: 'icon_adjuster' })} className={`group flex items-center gap-3 p-3 rounded-xl transition-all duration-300 relative ${state.activeTool === 'icon_adjuster' ? 'bg-blue-500/10 text-blue-400 border border-blue-500/20 shadow-lg' : 'text-zinc-400 hover:bg-zinc-800/50 hover:text-white'} ${state.isSidebarExpanded ? 'justify-center md:justify-start' : 'justify-center'}`}>
                <div className={`${state.activeTool === 'icon_adjuster' ? 'text-blue-400' : 'text-zinc-500 group-hover:text-zinc-300'}`}>
                    <div className="w-6 h-6 flex items-center justify-center"><div className="w-4 h-4 border-2 border-current rounded-sm"></div></div>
                </div>
                <div className={`hidden md:flex flex-col items-start text-left overflow-hidden whitespace-nowrap transition-all duration-300 ${state.isSidebarExpanded ? 'w-auto opacity-100' : 'w-0 opacity-0'}`}><span className="text-sm font-semibold">Icon Adjuster</span></div>
            </button>

            <button onClick={() => updateState({ activeTool: 'bg_remover' })} className={`group flex items-center gap-3 p-3 rounded-xl transition-all duration-300 relative ${state.activeTool === 'bg_remover' ? 'bg-pink-500/10 text-pink-400 border border-pink-500/20 shadow-lg' : 'text-zinc-400 hover:bg-zinc-800/50 hover:text-white'} ${state.isSidebarExpanded ? 'justify-center md:justify-start' : 'justify-center'}`}>
                <div className={`${state.activeTool === 'bg_remover' ? 'text-pink-400' : 'text-zinc-500 group-hover:text-zinc-300'}`}>
                    <MagicWandIcon className="w-6 h-6" />
                </div>
                <div className={`hidden md:flex flex-col items-start text-left overflow-hidden whitespace-nowrap transition-all duration-300 ${state.isSidebarExpanded ? 'w-auto opacity-100' : 'w-0 opacity-0'}`}><span className="text-sm font-semibold">BG Remover</span></div>
            </button>

            <button onClick={() => updateState({ activeTool: 'image_editor' })} className={`group flex items-center gap-3 p-3 rounded-xl transition-all duration-300 relative ${state.activeTool === 'image_editor' ? 'bg-amber-500/10 text-amber-400 border border-amber-500/20 shadow-lg' : 'text-zinc-400 hover:bg-zinc-800/50 hover:text-white'} ${state.isSidebarExpanded ? 'justify-center md:justify-start' : 'justify-center'}`}>
                <div className={`${state.activeTool === 'image_editor' ? 'text-amber-400' : 'text-zinc-500 group-hover:text-zinc-300'}`}>
                    <PhotoEditIcon className="w-6 h-6" />
                </div>
                <div className={`hidden md:flex flex-col items-start text-left overflow-hidden whitespace-nowrap transition-all duration-300 ${state.isSidebarExpanded ? 'w-auto opacity-100' : 'w-0 opacity-0'}`}><span className="text-sm font-semibold">Image Editor</span></div>
            </button>
            </>
        )}
      </nav>
    </aside>
  );
};
export default Sidebar;

import React from 'react';
import { AppState, GeneratedImage } from '../../types';
import { TRANSLATIONS } from '../../translations';
import { DownloadAllIcon, LayoutFeaturedIcon, LayoutGrid5Icon, LayoutGrid3Icon, LayoutGrid2Icon, UploadIcon, IdeaCreationIcon } from '../Icons';
import { ART_STYLES } from '../../data/common';

interface Props {
  state: AppState;
  updateState: (updates: Partial<AppState>) => void;
  latestImageRef: React.RefObject<HTMLDivElement>;
  handleImageClick: (img: GeneratedImage) => void;
  handleDownloadAll: () => void;
  handleDownloadAllZip: () => void;
}

// Component for handling individual item
const GalleryItem: React.FC<{ 
    img: GeneratedImage; 
    isActive: boolean; 
    onClick: () => void; 
    viewMode: string;
    language: string;
    t: any;
    innerRef?: React.Ref<HTMLDivElement>;
}> = ({ img, isActive, onClick, viewMode, language, t, innerRef }) => {
    return (
        <div 
            ref={innerRef}
            onClick={onClick} 
            className={`group relative rounded-xl overflow-hidden bg-zinc-900 border animate-fade-in-up cursor-pointer hover:border-zinc-600 transition-all ${isActive ? 'border-indigo-500 shadow-lg shadow-indigo-500/20' : 'border-zinc-800'} ${viewMode === 'featured' ? 'w-24 h-24 lg:w-full lg:h-auto lg:aspect-square opacity-60 hover:opacity-100' : (img.aspectRatio === '16:9' ? 'aspect-video' : img.aspectRatio === '9:16' ? 'aspect-[9/16]' : img.aspectRatio === '4:3' ? 'aspect-[4/3]' : img.aspectRatio === '3:4' ? 'aspect-[3/4]' : 'aspect-square')}`}
        >
            <img src={img.url} alt={img.prompt} className="w-full h-full object-cover transition duration-700 group-hover:scale-110" />

            {viewMode !== 'featured' && (
                <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/40 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex flex-col justify-end p-4 pointer-events-none">
                    <div className="flex items-center gap-2 mb-2">
                        <span className="text-[10px] uppercase font-bold bg-indigo-500 text-white px-2 py-0.5 rounded-sm">{t.modes[img.mode].label}</span>
                        <span className="text-[10px] uppercase font-bold bg-zinc-700 text-zinc-300 px-2 py-0.5 rounded-sm">{t.categories[img.category]}</span>
                    </div>
                    <p className="text-xs text-zinc-300 line-clamp-2">{img.prompt}</p>
                    {img.artStyle && img.artStyle !== 'none' && (<p className="text-[10px] text-indigo-300 mt-1">Style: {ART_STYLES.find(s => s.id === img.artStyle)?.label[language]}</p>)}
                </div>
            )}
        </div>
    );
};

const Gallery: React.FC<Props> = ({ state, updateState, latestImageRef, handleImageClick, handleDownloadAll, handleDownloadAllZip }) => {
  const t = TRANSLATIONS[state.language];

  const getActiveGalleryImage = () => {
    if (!state.galleryActiveImageId) return null;
    return state.generatedImages.find(img => img.id === state.galleryActiveImageId);
  };

  const activeImg = getActiveGalleryImage();

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between px-1">
         <h3 className="text-lg font-semibold text-zinc-400">{t.recent}</h3>
         <div className="flex gap-2">
            <button 
                onClick={handleDownloadAll}
                disabled={state.generatedImages.length === 0}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium border transition-colors ${state.generatedImages.length === 0 ? 'bg-zinc-900 border-zinc-800 text-zinc-600 cursor-not-allowed' : 'bg-zinc-900 border-zinc-800 text-zinc-300 hover:text-white hover:border-zinc-600'}`}
                title="Download all items as individual files"
            >
                <UploadIcon className="w-4 h-4 rotate-180" /><span className="hidden sm:inline">Files</span>
            </button>
            <button 
                onClick={handleDownloadAllZip}
                disabled={state.generatedImages.length === 0}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium border transition-colors ${state.generatedImages.length === 0 ? 'bg-zinc-900 border-zinc-800 text-zinc-600 cursor-not-allowed' : 'bg-zinc-900 border-zinc-800 text-zinc-300 hover:text-white hover:border-zinc-600'}`}
                title="Download all items as a ZIP archive"
            >
                <DownloadAllIcon className="w-4 h-4" /><span className="hidden sm:inline">ZIP</span>
            </button>
            <div className="bg-zinc-900 border border-zinc-800 rounded-lg p-1 flex gap-1">
                <button onClick={() => updateState({ galleryViewMode: 'featured' })} className={`p-1.5 rounded ${state.galleryViewMode === 'featured' ? 'bg-zinc-700 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}><LayoutFeaturedIcon className="w-4 h-4" /></button>
                <button onClick={() => updateState({ galleryViewMode: 'grid5' })} className={`p-1.5 rounded ${state.galleryViewMode === 'grid5' ? 'bg-zinc-700 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}><LayoutGrid5Icon className="w-4 h-4" /></button>
