    isEraser: boolean;
}

export interface FixData {
    maskHistory: MaskPath[];
    brushSize: number;
    selectionFeather: number;
    maskOpacity: number;
    maskColor: string;
    prompt: string;
}

export interface ExpandData {
    resizeFactor: number;
    placementX: number;
    placementY: number;
    prompt: string;
}

export interface UpscaleData {
    scale: '2k' | '4k';
    creativity: number;
}

export interface EditState {
    activeMode: EditModelMode;
    prompts: {
        fast: string;
        pro: string;
    };
    settings: {
        fast: {
            aspectRatio: AspectRatio;
            batchSize: number;
        };
        pro: {
            aspectRatio: AspectRatio;
            batchSize: number;
            resolution: ImageSize;
        };
    };
    fixData: FixData;
    expandData: ExpandData;
    upscaleData: UpscaleData;
}

