export const useAppLogic = () => {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activePopover, setActivePopover] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const autoFillInputRef = useRef<HTMLInputElement>(null);
  const hairRefInputRef = useRef<HTMLInputElement>(null);
  const latestImageRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const updateState = useCallback((updates: Partial<AppState> | ((prev: AppState) => Partial<AppState>)) => {
    setState((prev) => {
        const newValues = typeof updates === 'function' ? updates(prev) : updates;
        return { ...prev, ...(newValues as Partial<AppState>) };
    });
  }, []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateState({ referenceImage: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    const file = e.dataTransfer.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateState({ referenceImage: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const clearReferenceImage = () => updateState({ referenceImage: null });

  // Data Updaters
  const createUpdater = <T extends keyof AppState>(key: T) => (field: keyof AppState[T], value: any) => {
      updateState((prev) => ({
          ...prev,
          [key]: { ...(prev[key] as object), [field]: value }
      }));
  };

  const updateCharacterData = createUpdater('characterData');
  const updateEnvironmentData = createUpdater('environmentData');
  const updateGamePropsData = createUpdater('gamePropsData');
  const updateUserInterfaceData = createUpdater('userInterfaceData');
  const updateUIAssetData = createUpdater('uiAssetData');
  const updateIconDesignData = createUpdater('iconDesignData');
  const updateVariantData = createUpdater('variantData');
  const updateSoundEffectData = createUpdater('soundEffectData');

  const updateEditState = (updates: Partial<EditState>) => {
      updateState((prev) => ({
          ...prev,
          editState: { ...prev.editState, ...updates }
      }));
  };

  const updateCreatureMix = (id: string, key: string, value: any) => {
      updateState(prev => ({
          creatureMixes: prev.creatureMixes.map(mix => mix.id === id ? { ...mix, [key]: value } : mix)
      }));
  };

  const addCreatureMix = () => {
      updateState(prev => {
          if (prev.creatureMixes.length >= 4) return {};
          return { creatureMixes: [...prev.creatureMixes, { id: Date.now().toString(), name: '', percentage: 50 }] };
      });
  };

  const removeCreatureMix = (id: string) => {
      updateState(prev => {
          if (prev.creatureMixes.length <= 1) return {};
          return { creatureMixes: prev.creatureMixes.filter(m => m.id !== id) };
      });
  };

  const updateCreatureAdvanced = createUpdater('creatureAdvanced');

  const handleGeneratePalette = (overrideBase?: string) => {
      updateState(prev => {
          const base = overrideBase || prev.variantData.baseColor;
          const palette = calculateHarmonyPalette(base, prev.variantData.harmonyType);
          return {
              variantData: { ...prev.variantData, generatedPalette: palette, baseColor: base }
          };
      });
  };

  // --- Texture Generator Logic ---
  const handleTextureGridUpdate = (rows: number, cols: number) => {
      updateState(prev => {
          const currentCount = prev.textureGeneratorData.slots.length;
          const targetCount = rows * cols;
          let newSlots = [...prev.textureGeneratorData.slots];

          if (targetCount > currentCount) {
              for(let i = currentCount; i < targetCount; i++) {
                  newSlots.push({ id: Date.now().toString() + i, type: 'solid' as const, colors: ['#ffffff'], angle: 0 });
              }
          } else {
              newSlots = newSlots.slice(0, targetCount);
          }
          return { textureGeneratorData: { ...prev.textureGeneratorData, rows, cols, slots: newSlots } };
      });
  };

  const updateTextureSlot = (id: string, updates: Partial<TextureSlot>) => {
      updateState(prev => ({
          textureGeneratorData: {
              ...prev.textureGeneratorData,
              slots: prev.textureGeneratorData.slots.map(s => s.id === id ? { ...s, ...updates } : s)
          }
      }));
  };

  const randomizeSlot = (id: string) => {
      const randomColor = () => '#' + Math.floor(Math.random()*16777215).toString(16).padStart(6, '0');
      const isGradient = Math.random() > 0.5;
      updateTextureSlot(id, {
          type: isGradient ? ('gradient' as const) : ('solid' as const),
          colors: isGradient ? [randomColor(), randomColor()] : [randomColor()],
          angle: Math.floor(Math.random() * 360)
      });
  };

  const handleForceAngle = (id: string, angle: number) => {
      updateTextureSlot(id, { angle });
  };

  const handleVariantHue = (id: string) => {
      const slot = state.textureGeneratorData.slots.find(s => s.id === id);
      if (!slot) return;

      const newColors = slot.colors.map(col => randomizeHue(col));
      updateTextureSlot(id, { colors: newColors });
  };

  const handleTextureScan = (file: File, padding: number) => {
      const reader = new FileReader();
      reader.onload = (e) => {
          const img = new Image();
          img.onload = () => {
              const canvas = document.createElement('canvas');
              canvas.width = img.width;
              canvas.height = img.height;
              const ctx = canvas.getContext('2d');
              if (!ctx) return;
              ctx.drawImage(img, 0, 0);

              const rows = state.textureGeneratorData.rows;
              const cols = state.textureGeneratorData.cols;
              const slotW = img.width / cols;
              const slotH = img.height / rows;

              const newSlots = state.textureGeneratorData.slots.map((slot, index) => {
                  if (index >= rows * cols) return slot;

                  const r = Math.floor(index / cols);
                  const c = index % cols;

                  const x = c * slotW;
                  const y = r * slotH;

                  // Sample Top (Start)
                  const p1 = ctx.getImageData(x + slotW/2, y + padding, 1, 1).data;
                  const hex1 = rgbToHex(p1[0], p1[1], p1[2]);

                  // Sample Bottom (End)
                  const p2 = ctx.getImageData(x + slotW/2, y + slotH - padding, 1, 1).data;
                  const hex2 = rgbToHex(p2[0], p2[1], p2[2]);

                  return {
                      ...slot,
                      type: 'gradient' as const,
                      colors: [hex1, hex2],
                      angle: 90, // Vertical scan implies 90 deg
                      stops: [0, 100]
                  };
              });

              updateState(prev => ({
                  textureGeneratorData: { ...prev.textureGeneratorData, slots: newSlots }
              }));
          };
          img.src = e.target?.result as string;
      };
      reader.readAsDataURL(file);
  };

  const handleAITextureGenerate = async (mode: 'single' | 'all') => {
      const promptText = state.textureGeneratorData.texturePrompt;
      if (!promptText) {
          alert("Please enter a description for the palette.");
          return;
      }

      if (!process.env.API_KEY) {
           console.warn("API Key missing");
           const mockColors = ['#ff00ff', '#00ffff', '#ffff00'];
           // Mock logic for demo if no key
           updateState(prev => {
                const newSlots = prev.textureGeneratorData.slots.map(s => {
                    const shouldUpdate = mode === 'all' ? !s.locked : s.id === prev.textureGeneratorData.selectedSlotId;
                    if (shouldUpdate) {
                        return {
                            ...s,
                            type: 'gradient' as const,
                            colors: mockColors.sort(() => Math.random() - 0.5),
                            angle: Math.floor(Math.random() * 360)
                        };
                    }
                    return s;
                });
                return { textureGeneratorData: { ...prev.textureGeneratorData, slots: newSlots } };
           });
           return;
      }

      updateState({ isGenerating: true, generationStatus: 'Dreaming palettes...' });

      try {
          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

          const slotsToUpdate = mode === 'single' 
              ? state.textureGeneratorData.slots.filter(s => s.id === state.textureGeneratorData.selectedSlotId)
              : state.textureGeneratorData.slots.filter(s => !s.locked);

          if (slotsToUpdate.length === 0) {
               updateState({ isGenerating: false });
               return;
          }

          // Parallel generation
          const results = await Promise.all(slotsToUpdate.map(async (slot) => {
               try {
                   const response = await ai.models.generateContent({
                       model: 'gemini-2.5-flash',
                       contents: `Create a color palette of 3-5 hex codes representing the texture/theme: "${promptText}". Variation ${slot.id}.`,
                       config: {
                           responseMimeType: 'application/json',
                           responseSchema: {
                               type: Type.ARRAY,
                               items: { type: Type.STRING }
                           }
                       }
                   });
                   const colors = JSON.parse(response.text || '[]');
                   return { id: slot.id, colors };
               } catch (e) {
                   console.error(e);
                   return { id: slot.id, colors: null };
               }
          }));

          updateState(prev => {
              const newSlots = prev.textureGeneratorData.slots.map(s => {
                  const res = results.find(r => r.id === s.id);
                  if (res && res.colors && res.colors.length > 0) {
                      return {
                          ...s,
                          type: 'gradient' as const,
                          colors: res.colors,
                          angle: Math.floor(Math.random() * 360),
                          stops: undefined
                      };
                  }
                  return s;
              });
              return {
                  textureGeneratorData: { ...prev.textureGeneratorData, slots: newSlots },
                  isGenerating: false,
                  generationStatus: 'Done'
              };
          });

      } catch (error) {
          console.error(error);
          updateState({ isGenerating: false, generationStatus: 'Error' });
      }
  };

  const handleSaveJSON = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(state.textureGeneratorData));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href",     dataStr);
      downloadAnchorNode.setAttribute("download", "texture_grid.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  const handleLoadJSON = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = (event) => {
          try {
              const data = JSON.parse(event.target?.result as string);
              if (data && data.slots) {
                  updateState({ textureGeneratorData: data });
              }
          } catch (error) {
              console.error("Invalid JSON", error);
          }
      };
      reader.readAsText(file);
  };

  // --- Auto Fill ---
  const handleAutoFillClick = () => {
      autoFillInputRef.current?.click();
  };

  const onAutoFillFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
      alert("Auto Fill feature would analyze the image using Gemini Vision here.");
  };

  // --- Generation Logic ---
  const handleGenerate = async (overrideImageBase64?: string) => {
      if (state.isGenerating) return;
      updateState({ isGenerating: true, generationStatus: 'Starting...', completedCount: 0, totalBatchCount: state.mode === 'edit' ? state.editState.settings[state.editState.activeMode].batchSize : state.batchSize });

      try {
          let prompt = generatePrompt(state, TRANSLATIONS[state.language]);
          let total = state.batchSize;
          let modelToUse = state.selectedModel;
          let imageConfig: any = { aspectRatio: state.aspectRatio };

          // --- Special Logic for Edit Mode ---
          if (state.mode === 'edit') {
              const mode = state.editState.activeMode;
              prompt = state.editState.prompts[mode];
              total = state.editState.settings[mode].batchSize;

              if (mode === 'fast') {
                  modelToUse = 'gemini-2.5-flash-image';
                  imageConfig = { aspectRatio: state.editState.settings.fast.aspectRatio };
              } else {
                  modelToUse = 'gemini-3-pro-image-preview';
                  imageConfig = { 
                      aspectRatio: state.editState.settings.pro.aspectRatio,
                      imageSize: state.editState.settings.pro.resolution
                  };
              }
          } else {
              // Standard logic for other modes
              if (modelToUse === 'gemini-3-pro-image-preview') {
                  imageConfig.imageSize = state.imageSize;
              }
          }

          // --- Image Generation (Gemini) ---
          if (!process.env.API_KEY) {
              // Simulation Fallback
              console.warn("No API Key found");
              await new Promise(resolve => setTimeout(resolve, 2000));
              const mockImage: GeneratedImage = {
                  id: Date.now().toString(),
                  url: 'https://via.placeholder.com/1024',
                  prompt: prompt,
                  mode: state.mode,
                  category: state.category,
                  model: modelToUse,
                  aspectRatio: imageConfig.aspectRatio,
                  artStyle: state.artStyle
              };
              updateState(prev => ({
                  generatedImages: [...prev.generatedImages, mockImage],
                  completedCount: total
              }));
          } else {
              const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

              for (let i = 0; i < total; i++) {
                  updateState({ generationStatus: `Generating image ${i + 1}/${total}` });

                  const requestContents: any = { parts: [{ text: prompt }] };

                  // Logic for Edit Mode Image Injection
                  if (state.mode === 'edit' && state.referenceImage) {
                      const base64Data = state.referenceImage.split(',')[1];
                      requestContents.parts.push({
                          inlineData: {
                              mimeType: 'image/png', 
                              data: base64Data
                          }
                      });
                  }

                  const response = await ai.models.generateContent({
                      model: modelToUse,
                      contents: requestContents,
                      config: {
                          imageConfig: imageConfig
                      }
                  });

                  let imageUrl = '';
                  if (response && response.candidates && response.candidates[0].content.parts) {
                      for (const part of response.candidates[0].content.parts) {
                          if (part.inlineData) {
                              imageUrl = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
                              break;
                          }
                      }
                  }

                  if (imageUrl) {
                      const newImg: GeneratedImage = {
                          id: Date.now().toString() + i,
                          url: imageUrl,
                          prompt: prompt,
                          mode: state.mode,
                          category: state.category,
                          model: modelToUse,
                          aspectRatio: imageConfig.aspectRatio,
                          artStyle: state.artStyle
                      };
                      updateState(prev => ({
                          generatedImages: [...prev.generatedImages, newImg],
                          completedCount: prev.completedCount + 1
                      }));
                  }
              }
          }

      } catch (error) {
          console.error("Generation failed", error);
          alert("Generation failed. Please try a different model or prompt.");
      } finally {
          updateState({ isGenerating: false, generationStatus: 'Done' });
      }
  };

  // --- Icon Adjuster ---
  const handleIconUpload = (files: FileList) => {
      const newItems: IconItem[] = Array.from(files).map(file => ({
          id: Date.now().toString() + Math.random(),
          file,
          src: URL.createObjectURL(file),
          x: 0, y: 0, scale: 1,
          originalWidth: 512, originalHeight: 512
      }));

      newItems.forEach(item => {
          const img = new Image();
          img.onload = () => {
              item.originalWidth = img.naturalWidth;
              item.originalHeight = img.naturalHeight;
          };
          img.src = item.src;
      });

      updateState(prev => ({
          iconAdjusterData: {
              ...prev.iconAdjusterData,
              items: [...prev.iconAdjusterData.items, ...newItems]
          }
      }));
  };

  const updateIconAdjusterData = (updates: Partial<IconAdjusterData>) => {
      updateState(prev => ({
          iconAdjusterData: { ...prev.iconAdjusterData, ...updates }
      }));
  };

  const updateIconItem = (idOrIds: string | string[], updates: Partial<IconItem>) => {
      const ids = Array.isArray(idOrIds) ? idOrIds : [idOrIds];
      updateState(prev => ({
          iconAdjusterData: {
              ...prev.iconAdjusterData,
              items: prev.iconAdjusterData.items.map(item => ids.includes(item.id) ? { ...item, ...updates } : item)
          }
      }));
  };

  // --- BG Remover ---
  const updateBgRemoverData = (updates: Partial<BgRemoverData>) => {
      updateState(prev => ({
          bgRemoverData: { ...prev.bgRemoverData, ...updates }
      }));
  };

  // --- Image Editor ---
  const updateImageEditorData = (updates: Partial<ImageEditorData>) => {
      updateState(prev => ({
          imageEditorData: { ...prev.imageEditorData, ...updates }
      }));
  };

  // --- Audio Editor ---
  const updateAudioEditorData = (updates: Partial<AudioEditorData>) => {
      updateState((prev) => ({
          ...prev,
          audioEditorData: { ...prev.audioEditorData, ...updates }
      }));
  };

  // --- Tool Integration ---
  const handleSendToTool = (image: GeneratedImage, tool: 'icon_adjuster' | 'bg_remover' | 'image_editor', action?: 'new' | 'add') => {
      if (tool === 'icon_adjuster') {
          fetch(image.url).then(res => res.blob()).then(blob => {
              const file = new File([blob], `generated-${image.id}.png`, { type: 'image/png' });
              const newItem: IconItem = {
                  id: Date.now().toString(),
                  file,
                  src: image.url,
                  x: 0, y: 0, scale: 1,
                  originalWidth: 1024, originalHeight: 1024
              };
              updateState(prev => ({
                  mode: 'tools',
                  activeTool: 'icon_adjuster',
                  iconAdjusterData: { ...prev.iconAdjusterData, items: [...prev.iconAdjusterData.items, newItem] },
                  selectedImage: null
              }));
          });
      } else if (tool === 'bg_remover') {
          updateState({
              mode: 'tools',
              activeTool: 'bg_remover',
              bgRemoverData: { ...state.bgRemoverData, imageSrc: image.url, history: [], historyIndex: -1 },
              selectedImage: null
          });
      } else if (tool === 'image_editor') {
          fetch(image.url).then(res => res.blob()).then(blob => {
             const url = URL.createObjectURL(blob);
             const newLayer: EditorLayer = {
                 id: Date.now().toString(),
                 name: 'Imported Image',
                 type: 'image',
                 visible: true, locked: false, opacity: 100,
                 x: state.imageEditorData.canvasWidth/2, y: state.imageEditorData.canvasHeight/2,
                 width: 400, height: 400, rotation: 0,
                 src: url,
                 filters: { brightness: 100, contrast: 100, saturation: 100, blur: 0, hue: 0, sepia: 0, grayscale: 0 }
             };

             let newLayers = [...state.imageEditorData.layers];
             if (action === 'new') {
                 newLayers = [newLayer];
             } else {
                 newLayers.push(newLayer);
             }

             updateState({
                 mode: 'tools',
                 activeTool: 'image_editor',
                 imageEditorData: { ...state.imageEditorData, layers: newLayers },
                 selectedImage: null
             });
          });
      }
  };

  const handleSendRawImageToTool = (dataUrl: string, tool: 'icon_adjuster' | 'image_editor', action?: 'new' | 'add') => {
      if (tool === 'icon_adjuster') {
          fetch(dataUrl).then(res => res.blob()).then(blob => {
              const file = new File([blob], `processed.png`, { type: 'image/png' });
              const newItem: IconItem = {
                  id: Date.now().toString(),
                  file,
                  src: dataUrl,
                  x: 0, y: 0, scale: 1,
                  originalWidth: 1024, originalHeight: 1024
              };
              updateState(prev => ({
                  activeTool: 'icon_adjuster',
                  iconAdjusterData: { ...prev.iconAdjusterData, items: [...prev.iconAdjusterData.items, newItem] }
              }));
          });
      } else if (tool === 'image_editor') {
          const newLayer: EditorLayer = {
              id: Date.now().toString(),
              name: 'Processed Image',
              type: 'image',
              visible: true, locked: false, opacity: 100,
              x: state.imageEditorData.canvasWidth/2, y: state.imageEditorData.canvasHeight/2,
              width: 400, height: 400, rotation: 0,
              src: dataUrl,
              filters: { brightness: 100, contrast: 100, saturation: 100, blur: 0, hue: 0, sepia: 0, grayscale: 0 }
          };

          let newLayers = [...state.imageEditorData.layers];
          if (action === 'new') {
              newLayers = [newLayer];
          } else {
              newLayers.push(newLayer);
          }

          updateState(prev => ({
              activeTool: 'image_editor',
              imageEditorData: { ...prev.imageEditorData, layers: newLayers }
          }));
      }
  };

  return {
    state,
    activePopover,
    setActivePopover,
    fileInputRef,
    autoFillInputRef,
    hairRefInputRef,
    latestImageRef,
    canvasRef,
    updateState,
    handleFileUpload,
    handleDrop,
    clearReferenceImage,
    updateCharacterData,
    updateEnvironmentData,
    updateGamePropsData,
    updateUserInterfaceData,
    updateUIAssetData,
    updateIconDesignData,
    updateVariantData,
    updateSoundEffectData,
    handleGeneratePalette,
    updateCreatureMix,
    addCreatureMix,
    removeCreatureMix,
    updateCreatureAdvanced,
    handleTextureGridUpdate,
    updateTextureSlot,
    randomizeSlot,
    handleAutoFillClick,
    onAutoFillFileChange,
    handleGenerate,
    handleAITextureGenerate,
    handleSaveJSON,
    handleLoadJSON,
    handleIconUpload,
    updateIconAdjusterData,
    updateIconItem,
    updateBgRemoverData,
    updateImageEditorData,
    updateAudioEditorData,
    handleSendToTool,
    handleSendRawImageToTool,
    updateEditState,
    handleForceAngle,
    handleVariantHue,
    handleTextureScan
  };
};

import React, { useRef, useEffect } from 'react';
import { AppState, IconAdjusterData, IconItem, IconOverlay } from '../../types';
import { TRANSLATIONS } from '../../translations';
import { UploadIcon, DownloadAllIcon, CloseIcon, DeleteIcon, FileIcon } from '../../components/Icons';
import JSZip from 'jszip';

interface Props {
  state: AppState;
  handleIconUpload: (files: FileList) => void;
  updateIconAdjusterData: (updates: Partial<IconAdjusterData>) => void;
  updateIconItem: (idOrIds: string | string[], updates: Partial<IconItem>) => void;
}

const SingleIconCanvas: React.FC<{ 
    item: IconItem; 
    data: IconAdjusterData; 
    isSelected: boolean;
    onSelect: () => void;
    onDelete: () => void;
}> = ({ item, data, isSelected, onSelect, onDelete }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Promise-based image loader with error handling
        const loadImg = (src: string) => new Promise<HTMLImageElement | null>((resolve) => {
            const img = new Image();
            img.crossOrigin = "Anonymous";
            img.onload = () => resolve(img);
            img.onerror = () => {
                console.warn("Failed to load image:", src);
                resolve(null);
            };
            img.src = src;
        });

        const render = async () => {
            // Clear
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Background
            if (data.background === 'white') {
                ctx.fillStyle = '#ffffff';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
            } else if (data.background === 'black') {
                ctx.fillStyle = '#000000';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
            } else if (data.background === 'custom') {
                ctx.fillStyle = data.backgroundColor;
                ctx.fillRect(0, 0, canvas.width, canvas.height);
            }

            try {
                const [img, overlayImg] = await Promise.all([
                    loadImg(item.src),
                    item.overlay ? loadImg(item.overlay.src) : Promise.resolve(null)
                ]);

                if (!img) return;

                // --- 1. Draw Main Icon (with Stroke) ---
                const centerX = canvas.width / 2 + item.x;
                const centerY = canvas.height / 2 + item.y;
                const dw = img.naturalWidth * item.scale;
                const dh = img.naturalHeight * item.scale;
                const dx = centerX - dw / 2;
                const dy = centerY - dh / 2;

                if (data.strokeEnabled && data.strokeThickness > 0) {
                    ctx.save();
                    const thick = data.strokeThickness;
                    const steps = data.strokeSmoothness || 8;

                    ctx.shadowColor = data.strokeColor;
                    ctx.shadowBlur = data.strokeBlur || 0;

                    const offsets = [];
                    for (let i = 0; i < steps; i++) {
                        const angle = (i / steps) * 2 * Math.PI;
                        offsets.push([Math.cos(angle) * thick, Math.sin(angle) * thick]);
                    }

                    offsets.forEach(([ox, oy]) => {
                       ctx.shadowOffsetX = ox;
                       ctx.shadowOffsetY = oy;
                       ctx.drawImage(img, dx, dy, dw, dh);
                    });

                    ctx.restore();
                }

                ctx.drawImage(img, dx, dy, dw, dh);

                // --- 2. Draw Overlay (Top Layer) ---
                if (overlayImg && item.overlay) {
                    ctx.save();
                    ctx.translate(canvas.width / 2, canvas.height / 2);
                    ctx.translate(item.overlay.x, item.overlay.y);
                    ctx.rotate((item.overlay.rotation || 0) * Math.PI / 180);
                    ctx.scale(item.overlay.scale, item.overlay.scale);
                    ctx.drawImage(overlayImg, -overlayImg.naturalWidth / 2, -overlayImg.naturalHeight / 2);
                    ctx.restore();
                }

                // Draw Padding Guide
                if (data.fitPadding > 0) {
                    ctx.save();
                    ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
                    ctx.lineWidth = 1;
                    ctx.setLineDash([5, 5]);
                    const p = data.fitPadding;
                    ctx.strokeRect(p, p, canvas.width - p * 2, canvas.height - p * 2);
                    ctx.restore();
                }

            } catch (e) {
                console.error("Render error", e);
            }
        };

        render();

    }, [item, data]); 

    return (
        <div 
            className={`relative group border-2 rounded-lg overflow-hidden transition-all ${isSelected ? 'border-indigo-500 shadow-lg shadow-indigo-500/20 ring-1 ring-indigo-500' : 'border-zinc-800 hover:border-zinc-600'}`}
            onClick={onSelect}
        >
            <canvas 
                ref={canvasRef} 
                width={data.canvasWidth} 
                height={data.canvasHeight} 
                className="w-full h-auto bg-[url('https://grainy-gradients.vercel.app/noise.svg')] bg-opacity-5"
                style={{
                    backgroundImage: data.background === 'transparent' ? 'linear-gradient(45deg, #1f1f22 25%, transparent 25%), linear-gradient(-45deg, #1f1f22 25%, transparent 25%), linear-gradient(45deg, transparent 75%, #1f1f22 75%), linear-gradient(-45deg, transparent 75%, #1f1f22 75%)' : 'none',
                    backgroundSize: '20px 20px',
                    backgroundPosition: '0 0, 0 10px, 10px -10px, -10px 0px'
                }}
            />
            <button onClick={(e) => { e.stopPropagation(); onDelete(); }} className="absolute top-2 right-2 bg-black/60 hover:bg-red-500 text-white rounded-full p-1 opacity-0 group-hover:opacity-100 transition"><CloseIcon className="w-3 h-3" /></button>
        </div>
    );
};

const IconAdjuster: React.FC<Props> = ({ state, handleIconUpload, updateIconAdjusterData, updateIconItem }) => {
  const data = state.iconAdjusterData;
  const t = TRANSLATIONS[state.language];
  const fileInputRef = useRef<HTMLInputElement>(null);
  const overlayInputRef = useRef<HTMLInputElement>(null);

  const getTargetIds = () => {
      if (data.commandMode === 'all') {
          return data.items.map(i => i.id);
      }
      return data.selectedItemIds;
  };

  const primarySelectedItem = data.items.find(i => i.id === data.selectedItemIds[0]);

  const handleOverlayUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      const targetIds = getTargetIds();
      if (targetIds.length === 0) {
          alert("Select at least one item to add overlay.");
          return;
      }

      const url = URL.createObjectURL(file);
      const newOverlay: IconOverlay = {
          src: url,
          x: 0,
          y: 0,
          scale: 1,
          rotation: 0
      };

      updateIconItem(targetIds, { overlay: newOverlay });
      e.target.value = '';
  };

  const updateOverlayProp = (key: keyof IconOverlay, value: number) => {
      const targetIds = getTargetIds();
      const newItems = data.items.map(item => {
          if (targetIds.includes(item.id) && item.overlay) {
              return {
                  ...item,
                  overlay: { ...item.overlay, [key]: value }
              };
          }
          return item;
      });
      updateIconAdjusterData({ items: newItems });
  };

  const removeOverlay = () => {
      const targetIds = getTargetIds();
      const newItems = data.items.map(item => {
          if (targetIds.includes(item.id)) {
              const { overlay, ...rest } = item;
              return rest;
          }
          return item;
      });
      updateIconAdjusterData({ items: newItems });
  };

  const handleCropToContent = (item: IconItem) => {
      const img = new Image();
      img.crossOrigin = "Anonymous";
      img.src = item.src;
      img.onload = () => {
          const cvs = document.createElement('canvas');
          cvs.width = img.naturalWidth;
          cvs.height = img.naturalHeight;
          const ctx = cvs.getContext('2d');
          if(!ctx) return;
          ctx.drawImage(img, 0, 0);
          const pixels = ctx.getImageData(0,0, cvs.width, cvs.height).data;

          let minX = cvs.width, minY = cvs.height, maxX = 0, maxY = 0;
          let found = false;

          for(let y=0; y<cvs.height; y++) {
              for(let x=0; x<cvs.width; x++) {
                  const alpha = pixels[(y*cvs.width + x)*4 + 3];
                  if(alpha > data.cropThreshold) {
                      if(x < minX) minX = x;
                      if(x > maxX) maxX = x;
                      if(y < minY) minY = y;
                      if(y > maxY) maxY = y;
                      found = true;
                  }
              }
          }

          if(!found) return;

          const bw = maxX - minX + 1;
          const bh = maxY - minY + 1;
          const cx = minX + bw / 2;
          const cy = minY + bh / 2;

          const ox = img.naturalWidth / 2;
          const oy = img.naturalHeight / 2;
          const vx = cx - ox;
          const vy = cy - oy;

          const availableW = data.canvasWidth - (data.fitPadding * 2);
          const availableH = data.canvasHeight - (data.fitPadding * 2);
          const scaleW = availableW / bw;
          const scaleH = availableH / bh;
          const newScale = Math.min(scaleW, scaleH);

          updateIconItem(item.id, {
              scale: newScale,
              x: -vx * newScale,
              y: -vy * newScale
          });
      };
  };

  const handleAutoFitCenter = (item: IconItem) => {
      const availableW = data.canvasWidth - (data.fitPadding * 2);
      const availableH = data.canvasHeight - (data.fitPadding * 2);
      const scaleW = availableW / item.originalWidth;
      const scaleH = availableH / item.originalHeight;
      const newScale = Math.min(scaleW, scaleH);

      updateIconItem(item.id, { scale: newScale, x: 0, y: 0 });
  };

  const handleAlignCenter = (item: IconItem) => {
      updateIconItem(item.id, { x: 0, y: 0 });
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        const targetIds = getTargetIds();
        if (targetIds.length === 0) return;

        const move = data.moveStep;
        const scaleStep = data.scaleStep;
        const key = e.key.toLowerCase();

        // W/A/S/D for move, Q/E for scale, R for crop
        if (['w','a','s','d','q','e','r'].includes(key)) {
            e.preventDefault();
        }

        data.items.forEach(item => {
            if (targetIds.includes(item.id)) {
                let updates: Partial<IconItem> | null = null;
                switch(key) {
                    case 'w': updates = { y: item.y - move }; break;
                    case 's': updates = { y: item.y + move }; break;
                    case 'a': updates = { x: item.x - move }; break;
                    case 'd': updates = { x: item.x + move }; break;
                    case 'q': updates = { scale: Math.max(0.01, item.scale - scaleStep) }; break;
                    case 'e': updates = { scale: item.scale + scaleStep }; break;
                    case 'r': handleCropToContent(item); break;
                }
                if (updates) {
                    updateIconItem(item.id, updates);
                }
            }
        });
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [data.selectedItemIds, data.commandMode, data.items, data.moveStep, data.scaleStep, data.canvasWidth, data.canvasHeight, data.fitPadding, data.cropThreshold]);

  const handleItemClick = (id: string) => {
      if (data.commandMode === 'one') {
          updateIconAdjusterData({ selectedItemIds: [id] });
      } else if (data.commandMode === 'multi') {
          if (data.selectedItemIds.includes(id)) {
              updateIconAdjusterData({ selectedItemIds: data.selectedItemIds.filter(sid => sid !== id) });
          } else {
              updateIconAdjusterData({ selectedItemIds: [...data.selectedItemIds, id] });
          }
      } else {
          updateIconAdjusterData({ selectedItemIds: [id] });
      }
  };

  const renderItemToCanvas = (item: IconItem, ctx: CanvasRenderingContext2D) => {
      return new Promise<void>(async (resolve) => {
          const loadImg = (src: string) => new Promise<HTMLImageElement | null>((resolve) => {
              const img = new Image();
              img.crossOrigin = "Anonymous";
              img.onload = () => resolve(img);
              img.onerror = () => resolve(null);
              img.src = src;
          });

          ctx.clearRect(0, 0, data.canvasWidth, data.canvasHeight);

          if (data.background === 'white') {
              ctx.fillStyle = '#ffffff';
              ctx.fillRect(0, 0, data.canvasWidth, data.canvasHeight);
          } else if (data.background === 'black') {
              ctx.fillStyle = '#000000';
              ctx.fillRect(0, 0, data.canvasWidth, data.canvasHeight);
          } else if (data.background === 'custom') {
              ctx.fillStyle = data.backgroundColor;
              ctx.fillRect(0, 0, data.canvasWidth, data.canvasHeight);
          }

          try {
              const [img, overlayImg] = await Promise.all([
                  loadImg(item.src),
                  item.overlay ? loadImg(item.overlay.src) : Promise.resolve(null)
              ]);

              if (!img) { resolve(); return; }

              const centerX = data.canvasWidth / 2 + item.x;
              const centerY = data.canvasHeight / 2 + item.y;
              const dw = img.naturalWidth * item.scale;
              const dh = img.naturalHeight * item.scale;
              const dx = centerX - dw / 2;
              const dy = centerY - dh / 2;

              if (data.strokeEnabled && data.strokeThickness > 0) {
                  ctx.save();
                  const thick = data.strokeThickness;
                  const steps = data.strokeSmoothness || 8;
                  ctx.shadowColor = data.strokeColor;
                  ctx.shadowBlur = data.strokeBlur || 0;
                  const offsets = [];
                  for (let i = 0; i < steps; i++) {
                      const angle = (i / steps) * 2 * Math.PI;
                      offsets.push([Math.cos(angle) * thick, Math.sin(angle) * thick]);
                  }
                  offsets.forEach(([ox, oy]) => {
                      ctx.shadowOffsetX = ox; ctx.shadowOffsetY = oy;
                      ctx.drawImage(img, dx, dy, dw, dh);
                  });
                  ctx.restore();
              }
              ctx.drawImage(img, dx, dy, dw, dh);

              if (overlayImg && item.overlay) {
                  ctx.save();
                  ctx.translate(data.canvasWidth / 2, data.canvasHeight / 2);
                  ctx.translate(item.overlay.x, item.overlay.y);
                  ctx.rotate((item.overlay.rotation || 0) * Math.PI / 180);
                  ctx.scale(item.overlay.scale, item.overlay.scale);
                  ctx.drawImage(overlayImg, -overlayImg.naturalWidth / 2, -overlayImg.naturalHeight / 2);
                  ctx.restore();
              }
              resolve();
          } catch (e) { resolve(); }
      });
  };

  const handleSaveAll = async () => {
    const tempCanvas = document.createElement('canvas');
    tempCanvas.width = data.canvasWidth;
    tempCanvas.height = data.canvasHeight;
    const ctx = tempCanvas.getContext('2d');
    if (!ctx) return;

    for (const item of data.items) {
        await renderItemToCanvas(item, ctx);
        const link = document.createElement('a');
        const originalName = item.file.name.replace(/\.[^/.]+$/, "");
        link.download = `${originalName}.png`;
        link.href = tempCanvas.toDataURL('image/png');
        link.click();
        await new Promise(r => setTimeout(r, 200)); 
    }
  };

  const handleSaveZip = async () => {
      const zip = new JSZip();
      const tempCanvas = document.createElement('canvas');
      tempCanvas.width = data.canvasWidth;
      tempCanvas.height = data.canvasHeight;
      const ctx = tempCanvas.getContext('2d');
      if (!ctx) return;

      for (const item of data.items) {
          await renderItemToCanvas(item, ctx);
          const base64Data = tempCanvas.toDataURL('image/png').split(',')[1];
          const originalName = item.file.name.replace(/\.[^/.]+$/, "");
          zip.file(`${originalName}.png`, base64Data, { base64: true });
      }

      const content = await zip.generateAsync({ type: "blob" });
      const url = URL.createObjectURL(content);
      const link = document.createElement('a');
      link.href = url;
      link.download = "sandria_icons.zip";
      link.click();
  };

  const handleClearAll = () => {
      if (window.confirm("Are you sure you want to clear all images?")) {
          updateIconAdjusterData({ items: [], selectedItemIds: [] });
      }
  };

  return (
    <div className="flex flex-col md:flex-row h-full overflow-hidden animate-fade-in-up">
        {/* Sidebar Settings */}
        <div className="w-full md:w-80 bg-zinc-900/50 backdrop-blur-md border-r border-zinc-800 p-6 overflow-y-auto custom-scrollbar flex flex-col gap-6">
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <span className="text-blue-400">🖼️</span> {t.iconAdjuster.title}
            </h2>

            <div 
